// Helper functions for working with mock data
export const getUserById = (userId) => {
  return mockUsers.find(user => user.userID === userId);
};

export const getSessionById = (sessionId) => {
  return mockSessions.find(session => session.sessionID === sessionId);
};

export const getSpaceById = (spaceId) => {
  return mockSpaces.find(space => space.spaceID === spaceId);
};

export const getResourceById = (resourceId) => {
  return mockResources.find(resource => resource.resourceID === resourceId);
};

export const getUserNotifications = (userId) => {
  return mockMessages.filter(message => 
    message.toUserID === userId || 
    message.broadcastScope === 'SYSTEM_WIDE' ||
    (message.broadcastScope === 'SPACE_MEMBERS' && getUserSpaces(userId).some(space => space.spaceID === message.broadcastTargetID))
  ).sort((a, b) => new Date(b.createdDate) - new Date(a.createdDate));
};

export const getUserBookmarks = (userId) => {
  const userBookmarkIds = mockResourceBookmarks
    .filter(bookmark => bookmark.userID === userId)
    .map(bookmark => bookmark.resourceID);
  
  return mockResources.filter(resource => 
    userBookmarkIds.includes(resource.resourceID)
  );
};

// Session bookmark helper functions for TASK 4
export const getUserSessionBookmarks = (userId) => {
  return mockSessionBookmarks
    .filter(bookmark => bookmark.userID === userId)
    .map(bookmark => ({
      ...bookmark,
      session: getSessionById(bookmark.sessionID)
    }))
    .filter(bookmark => bookmark.session); // Filter out bookmarks for non-existent sessions
};

export const isSessionBookmarked = (userId, sessionId) => {
  return mockSessionBookmarks.some(bookmark => 
    bookmark.userID === userId && bookmark.sessionID === sessionId
  );
};

export const addSessionBookmark = (userId, sessionId, notes = '') => {
  if (isSessionBookmarked(userId, sessionId)) {
    return false; // Already bookmarked
  }
  
  const newBookmark = {
    bookmarkID: `bookmark_session_${Date.now()}`,
    userID: userId,
    sessionID: sessionId,
    bookmarkedDate: new Date().toISOString(),
    notes: notes
  };
  
  mockSessionBookmarks.push(newBookmark);
  return true;
};

export const removeSessionBookmark = (userId, sessionId) => {
  const index = mockSessionBookmarks.findIndex(bookmark => 
    bookmark.userID === userId && bookmark.sessionID === sessionId
  );
  
  if (index !== -1) {
    mockSessionBookmarks.splice(index, 1);
    return true;
  }
  return false;
};

export const getSessionRegistrations = (sessionId) => {
  const session = getSessionById(sessionId);
  return session ? session.registrations : [];
};

export const isUserRegisteredForSession = (userId, sessionId) => {
  const registrations = getSessionRegistrations(sessionId);
  return registrations.some(reg => reg.userID === userId);
};

