// Check if user can broadcast to session participants
export const canUserBroadcastToSession = (userId, sessionId) => {
  const session = getSessionById(sessionId);
  if (!session) return false;
  
  const user = getUserById(userId);
  if (!user) return false;
  
  // Teacher, host, or system admin can broadcast
  return session.teacherID === userId || 
         session.hostID === userId ||
         user.roles.includes('SYS_ADMIN');
};

// Check if user can broadcast to space members
export const canUserBroadcastToSpace = (userId, spaceId) => {
  const space = getSpaceById(spaceId);
  if (!space) return false;
  
  const user = getUserById(userId);
  if (!user) return false;
  
  // Space moderator or system admin can broadcast
  return space.moderatorIDs?.includes(userId) ||
         user.roles.includes('SYS_ADMIN');
};

