// Get spaces a user belongs to
export const getUserSpaces = (userId) => {
  // For demo, return spaces based on user type
  const user = getUserById(userId);
  if (!user) return [];
  
  if (user.roles.includes('TEACHER') || user.roles.includes('SYS_ADMIN')) {
    return mockSpaces; // Teachers and admins can access all spaces
  }
  
  // Session hosts get specific spaces based on their assignments
  if (user.roles.includes('SESSION_HOST')) {
    if (userId === 'user_003' || userId === 'user_004' || userId === 'user_005' || userId === 'user_006') {
      return mockSpaces.filter(space => space.spaceID === 'space_001'); // English space hosts
    }
    if (userId === 'user_007' || userId === 'user_008') {
      return mockSpaces.filter(space => space.spaceID === 'space_003'); // Vietnamese space hosts
    }
  }
  
  // Students get specific spaces based on their profile
  return mockSpaces.filter(space => {
    if (userId === 'user_009') return space.spaceID === 'space_001'; // Anna Student - English space
    return space.spaceID === 'space_001'; // Default to first space
  });
}; 