import React, { useState } from 'react';
import {
  Container,
  Card,
  CardContent,
  Typography,
  Button,
  Box,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Divider,
  IconButton,
  Tabs,
  Tab,
  Menu,
  MenuItem,
  Alert
} from '@mui/material';
import {
  Notifications,

  Announcement,
  Schedule,
  MoreVert,
  MarkAsUnread,
  Delete,
  Archive,
  AccessTime,
  Person,
  NotificationsActive,
  DoneAll
} from '@mui/icons-material';
import { format } from 'date-fns';
import { getUserEvents, currentUser, getUserById } from '../../data/mockData';

const NotificationsPage = () => {
  const [tabValue, setTabValue] = useState(0);
  const [menuAnchor, setMenuAnchor] = useState(null);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [events, setEvents] = useState(getUserEvents(currentUser.userID));

  // Filter events by type
  const allEvents = events;
  const unreadEvents = events.filter(event => !event.isRead);
  const announcementEvents = events.filter(event => 
    (event.messageType || event.eventType) === 'ANNOUNCEMENT'
  );
  const reminderEvents = events.filter(event => 
    (event.messageType || event.eventType) === 'REMINDER'
  );

  const getEventsByTab = () => {
    switch (tabValue) {
      case 0: return allEvents;
      case 1: return unreadEvents;
      case 2: return announcementEvents;
      case 3: return reminderEvents;
      default: return allEvents;
    }
  };

  const handleMenuOpen = (event, eventItem) => {
    setMenuAnchor(event.currentTarget);
    setSelectedEvent(eventItem);
  };

  const handleMenuClose = () => {
    setMenuAnchor(null);
    setSelectedEvent(null);
  };

  const markAsRead = (eventId) => {
    setEvents(events.map(event => 
      event.eventID === eventId ? { ...event, isRead: true } : event
    ));
    handleMenuClose();
  };

  const markAsUnread = (eventId) => {
    setEvents(events.map(event => 
      event.eventID === eventId ? { ...event, isRead: false } : event
    ));
    handleMenuClose();
  };

  const deleteEvent = (eventId) => {
    setEvents(events.filter(event => event.eventID !== eventId));
    handleMenuClose();
  };

  const markAllAsRead = () => {
    setEvents(events.map(event => ({ ...event, isRead: true })));
  };

  const getEventIcon = (type, priority) => {
    const iconProps = {
      sx: { 
        bgcolor: type === 'ANNOUNCEMENT' ? 'info.main' : 
                type === 'REMINDER' ? 'warning.main' : 'primary.main',
        ...(priority === 'HIGH' && { 
          animation: 'pulse 2s infinite',
          '@keyframes pulse': {
            '0%': { transform: 'scale(1)' },
            '50%': { transform: 'scale(1.1)' },
            '100%': { transform: 'scale(1)' }
          }
        })
      }
    };

    switch (type) {
      case 'ANNOUNCEMENT':
        return <Avatar {...iconProps}><Announcement /></Avatar>;
      case 'REMINDER':
        return <Avatar {...iconProps}><Schedule /></Avatar>;
      default:
        return <Avatar {...iconProps}><Notifications /></Avatar>;
    }
  };

  const EventItem = ({ event }) => {
    const fromUser = event.fromUserID ? getUserById(event.fromUserID) : null;
    
    return (
      <ListItem 
        sx={{ 
          px: 0,
          opacity: event.isRead ? 0.7 : 1,
          bgcolor: !event.isRead ? 'action.hover' : 'transparent',
          borderRadius: 1,
          mb: 1
        }}
      >
        <ListItemAvatar>
          {getEventIcon(event.messageType || event.eventType || 'NOTIFICATION', event.priority)}
        </ListItemAvatar>
        
        <ListItemText
          primary={
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <Typography 
                variant="body1" 
                sx={{ fontWeight: event.isRead ? 400 : 600, flex: 1 }}
              >
                {event.title}
              </Typography>
              {event.priority === 'HIGH' && (
                <Chip label="High Priority" size="small" color="error" />
              )}
              {!event.isRead && (
                <Box sx={{ width: 8, height: 8, bgcolor: 'primary.main', borderRadius: '50%' }} />
              )}
            </Box>
          }
          secondary={
            <Box sx={{ mt: 1 }}>
              <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                {event.content}
              </Typography>
              
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                  <AccessTime sx={{ fontSize: 16 }} />
                  <Typography variant="caption" color="text.secondary">
                    {format(new Date(event.createdDate), 'MMM dd, yyyy HH:mm')}
                  </Typography>
                </Box>
                
                {fromUser && (
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    <Person sx={{ fontSize: 16 }} />
                    <Typography variant="caption" color="text.secondary">
                      {fromUser.firstName} {fromUser.lastName}
                    </Typography>
                  </Box>
                )}
                
                <Chip 
                  label={(event.messageType || event.eventType || 'NOTIFICATION').replace('_', ' ')}
                  size="small"
                  variant="outlined"
                />
              </Box>
            </Box>
          }
        />
        
        <IconButton 
          size="small" 
          onClick={(e) => handleMenuOpen(e, event)}
        >
          <MoreVert />
        </IconButton>
      </ListItem>
    );
  };

  return (
    <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
      {/* Header */}
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box>
          <Typography variant="h4" sx={{ fontWeight: 600, mb: 1 }}>
            Notifications
          </Typography>
          <Typography variant="body1" color="text.secondary">
            Stay updated with announcements and session reminders
          </Typography>
        </Box>
        
        {unreadEvents.length > 0 && (
          <Button 
            variant="outlined"
            startIcon={<DoneAll />}
            onClick={markAllAsRead}
          >
            Mark All Read
          </Button>
        )}
      </Box>

      {/* Summary Cards */}
      <Box sx={{ display: 'flex', gap: 2, mb: 3, flexWrap: 'wrap' }}>
        <Card sx={{ flex: 1, minWidth: 200 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <NotificationsActive sx={{ fontSize: 40, color: 'primary.main', mb: 1 }} />
            <Typography variant="h5" sx={{ fontWeight: 600 }}>
              {unreadEvents.length}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Unread Notifications
            </Typography>
          </CardContent>
        </Card>
        
        <Card sx={{ flex: 1, minWidth: 200 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Announcement sx={{ fontSize: 40, color: 'info.main', mb: 1 }} />
            <Typography variant="h5" sx={{ fontWeight: 600 }}>
              {announcementEvents.length}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Announcements
            </Typography>
          </CardContent>
        </Card>
        
        <Card sx={{ flex: 1, minWidth: 200 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Schedule sx={{ fontSize: 40, color: 'warning.main', mb: 1 }} />
            <Typography variant="h5" sx={{ fontWeight: 600 }}>
              {reminderEvents.length}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Reminders
            </Typography>
          </CardContent>
        </Card>
      </Box>

      {/* Tabs */}
      <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}>
        <Tabs value={tabValue} onChange={(e, newValue) => setTabValue(newValue)}>
          <Tab label={`All (${allEvents.length})`} />
          <Tab 
            label={`Unread (${unreadEvents.length})`}
            icon={unreadEvents.length > 0 ? <NotificationsActive /> : null}
          />
          <Tab label={`Announcements (${announcementEvents.length})`} />
          <Tab label={`Reminders (${reminderEvents.length})`} />
        </Tabs>
      </Box>

      {/* Notifications List */}
      <Card>
        <CardContent>
          {getEventsByTab().length === 0 ? (
            <Box sx={{ textAlign: 'center', py: 6 }}>
              <Notifications sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" color="text.secondary" sx={{ mb: 1 }}>
                No notifications found
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {tabValue === 1 ? 'All caught up! No unread notifications.' : 
                 'You\'ll receive notifications for session reminders and community announcements.'}
              </Typography>
            </Box>
          ) : (
            <List disablePadding>
              {getEventsByTab().map((event, index) => (
                <React.Fragment key={event.eventID}>
                  <EventItem event={event} />
                  {index < getEventsByTab().length - 1 && <Divider sx={{ my: 1 }} />}
                </React.Fragment>
              ))}
            </List>
          )}
        </CardContent>
      </Card>

      {/* Notification Settings Alert */}
      <Alert severity="info" sx={{ mt: 3 }}>
        <Typography variant="body2">
          💡 <strong>Tip:</strong> You can customize your notification preferences in your profile settings. 
          Choose when to receive session reminders and which types of announcements you'd like to see.
        </Typography>
      </Alert>

      {/* Context Menu */}
      <Menu
        anchorEl={menuAnchor}
        open={Boolean(menuAnchor)}
        onClose={handleMenuClose}
      >
        {selectedEvent && (
          [
            selectedEvent.isRead ? (
              <MenuItem key="unread" onClick={() => markAsUnread(selectedEvent.eventID)}>
                <MarkAsUnread sx={{ mr: 2 }} />
                Mark as Unread
              </MenuItem>
            ) : (
              <MenuItem key="read" onClick={() => markAsRead(selectedEvent.eventID)}>
                <DoneAll sx={{ mr: 2 }} />
                Mark as Read
              </MenuItem>
            ),
            <MenuItem key="archive" onClick={handleMenuClose}>
              <Archive sx={{ mr: 2 }} />
              Archive
            </MenuItem>,
            <MenuItem key="delete" onClick={() => deleteEvent(selectedEvent.eventID)}>
              <Delete sx={{ mr: 2 }} />
              Delete
            </MenuItem>
          ]
        )}
      </Menu>
    </Container>
  );
};

export default NotificationsPage; 