import React, { useState } from 'react';
import { Outlet, useLocation, useNavigate } from 'react-router-dom';
import {
  Box,
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Badge,
  BottomNavigation,
  BottomNavigationAction,
  Menu,
  MenuItem,
  Avatar,
  Snackbar,
  Alert,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,

} from '@mui/material';
import {
  HomeOutlined,
  EventOutlined,
  LibraryBooksOutlined,
  PersonOutlined,
  NotificationsOutlined,
  LogoutOutlined,
  AdminPanelSettingsOutlined,
  MenuOutlined,
  LanguageOutlined,
  SpaceBarOutlined
} from '@mui/icons-material';
import { styled } from '@mui/material/styles';
// const useTheme = () => {}; // Reserved for theming
import { useTranslation } from 'react-i18next';
import { useAuth } from '../../contexts/AuthContext';
import { useNotification } from '../../contexts/NotificationContext';
import { mockUsers } from '../../data/mockData';

const MainContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  minHeight: '100vh',
  backgroundColor: theme.palette.background.default,
}));

const ContentArea = styled(Box)(({ theme }) => ({
  flex: 1,
  paddingTop: theme.spacing(8), // Space for AppBar
  paddingBottom: theme.spacing(7), // Space for BottomNavigation
  overflow: 'auto',
}));

const StyledBottomNavigation = styled(BottomNavigation)(({ theme }) => ({
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  zIndex: theme.zIndex.appBar,
  borderTop: `1px solid ${theme.palette.divider}`,
  backgroundColor: theme.palette.background.paper,
}));

const UserAvatar = styled(Avatar)(({ theme }) => ({
  width: 32,
  height: 32,
  backgroundColor: theme.palette.primary.main,
  fontSize: '0.875rem',
}));

function MobileLayout() {
  const { t, i18n } = useTranslation();
  const { user, logout, hasRole, switchUserForDemo } = useAuth();
  const { snackbar, hideSnackbar, unreadCount } = useNotification();
  const location = useLocation();
  const navigate = useNavigate();
  // const theme = useTheme(); // Reserved for future theming

  const [anchorEl, setAnchorEl] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  // const [darkMode, setDarkMode] = useState(false); // Reserved for dark mode toggle

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    logout();
    handleMenuClose();
  };

  const handleNavigate = (path) => {
    navigate(path);
    setDrawerOpen(false);
  };

  const getBottomNavValue = () => {
    const path = location.pathname;
    if (path === '/') return 0;
    if (path.startsWith('/sessions')) return 1;
    if (path.startsWith('/resources')) return 2;
    if (path.startsWith('/profile')) return 3;
    return 0;
  };

  const handleBottomNavChange = (event, newValue) => {
    const paths = ['/', '/sessions', '/resources', '/profile'];
    navigate(paths[newValue]);
  };

  const getUserInitials = () => {
    if (!user) return 'U';
    return `${user.firstName?.charAt(0) || ''}${user.lastName?.charAt(0) || ''}`.toUpperCase();
  };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/') return 'Home';
    if (path.startsWith('/sessions')) return t('sessions');
    if (path.startsWith('/resources')) return t('resources');
    if (path.startsWith('/profile')) return t('profile');
    if (path.startsWith('/notifications')) return t('notifications');
    if (path.startsWith('/spaces')) return t('learningSpaces');
    return 'Gakuto';
  };

  const handleLanguageChange = (lang) => {
    i18n.changeLanguage(lang);
    localStorage.setItem('language', lang);
    setDrawerOpen(false);
  };

  const handleDemoUserSwitch = (userId) => {
    switchUserForDemo(userId);
    setDrawerOpen(false);
  };

  return (
    <MainContainer>
      {/* Top App Bar */}
      <AppBar position="fixed" elevation={1}>
        <Toolbar>
          <IconButton
            edge="start"
            color="inherit"
            onClick={() => setDrawerOpen(true)}
            sx={{ mr: 2 }}
          >
            <MenuOutlined />
          </IconButton>

          <Typography
            variant="h6"
            component="div"
            sx={{
              flexGrow: 1,
              fontFamily: '"Noto Serif", serif',
              fontWeight: 600
            }}
          >
            {getPageTitle()}
          </Typography>

          <IconButton
            color="inherit"
            onClick={() => navigate('/notifications')}
            sx={{ mr: 1 }}
          >
            <Badge badgeContent={unreadCount} color="error">
              <NotificationsOutlined />
            </Badge>
          </IconButton>

          <IconButton
            color="inherit"
            onClick={handleMenuOpen}
            size="small"
          >
            <UserAvatar>
              {getUserInitials()}
            </UserAvatar>
          </IconButton>
        </Toolbar>
      </AppBar>

      {/* User Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
        transformOrigin={{ horizontal: 'right', vertical: 'top' }}
        anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
      >
        <MenuItem disabled>
          <Typography variant="body2" color="textSecondary">
            {user?.firstName} {user?.lastName}
          </Typography>
        </MenuItem>
        <MenuItem disabled>
          <Typography variant="caption" color="textSecondary">
            {user?.roles?.join(', ')}
          </Typography>
        </MenuItem>
        <Divider />
        <MenuItem onClick={() => { navigate('/profile'); handleMenuClose(); }}>
          <PersonOutlined sx={{ mr: 1 }} />
          {t('profile')}
        </MenuItem>
        {(hasRole('TEACHER') || hasRole('SYS_ADMIN')) && (
          <MenuItem onClick={() => { navigate('/admin'); handleMenuClose(); }}>
            <AdminPanelSettingsOutlined sx={{ mr: 1 }} />
            Admin
          </MenuItem>
        )}
        <MenuItem onClick={handleLogout}>
          <LogoutOutlined sx={{ mr: 1 }} />
          {t('logout')}
        </MenuItem>
      </Menu>

      {/* Side Drawer */}
      <Drawer
        anchor="left"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
      >
        <Box sx={{ width: 280, p: 2 }}>
          <Typography variant="h6" sx={{ mb: 2, fontFamily: '"Noto Serif", serif' }}>
            Gakuto
          </Typography>
          
          <Divider sx={{ mb: 2 }} />
          
          <List>
            <ListItem button onClick={() => handleNavigate('/')}>
              <ListItemIcon><HomeOutlined /></ListItemIcon>
              <ListItemText primary={t('home')} />
            </ListItem>
            <ListItem button onClick={() => handleNavigate('/sessions')}>
              <ListItemIcon><EventOutlined /></ListItemIcon>
              <ListItemText primary={t('sessions')} />
            </ListItem>
            <ListItem button onClick={() => handleNavigate('/resources')}>
              <ListItemIcon><LibraryBooksOutlined /></ListItemIcon>
              <ListItemText primary={t('resources')} />
            </ListItem>
            <ListItem button onClick={() => handleNavigate('/spaces')}>
              <ListItemIcon><SpaceBarOutlined /></ListItemIcon>
              <ListItemText primary={t('learningSpaces')} />
            </ListItem>
            <ListItem button onClick={() => handleNavigate('/notifications')}>
              <ListItemIcon>
                <Badge badgeContent={unreadCount} color="error">
                  <NotificationsOutlined />
                </Badge>
              </ListItemIcon>
              <ListItemText primary={t('notifications')} />
            </ListItem>
          </List>
          
          <Divider sx={{ my: 2 }} />
          
          {/* Language Selection */}
          <Typography variant="subtitle2" sx={{ mb: 1, color: 'text.secondary' }}>
            {t('language')}
          </Typography>
          <List dense>
            {[
              { code: 'en', name: 'English' },
              { code: 'ja', name: '日本語' },
              { code: 'fr', name: 'Français' },
              { code: 'es', name: 'Español' },
              { code: 'vi', name: 'Tiếng Việt' }
            ].map(lang => (
              <ListItem
                key={lang.code}
                button
                selected={i18n.language === lang.code}
                onClick={() => handleLanguageChange(lang.code)}
              >
                <ListItemIcon><LanguageOutlined /></ListItemIcon>
                <ListItemText primary={lang.name} />
              </ListItem>
            ))}
          </List>
          
          <Divider sx={{ my: 2 }} />
          
          {/* Demo User Switcher */}
          <Typography variant="subtitle2" sx={{ mb: 1, color: 'text.secondary' }}>
            Demo Users
          </Typography>
          <List dense>
            {mockUsers.map(demoUser => (
              <ListItem
                key={demoUser.userID}
                button
                selected={user?.userID === demoUser.userID}
                onClick={() => handleDemoUserSwitch(demoUser.userID)}
              >
                <ListItemIcon>
                  <Avatar sx={{ width: 24, height: 24, fontSize: '0.75rem' }}>
                    {demoUser.firstName?.charAt(0) || 'U'}
                  </Avatar>
                </ListItemIcon>
                <ListItemText
                  primary={`${demoUser.firstName} ${demoUser.lastName} (${demoUser.roles.join(', ')})`}
                  secondary={demoUser.email}
                />
              </ListItem>
            ))}
          </List>
        </Box>
      </Drawer>

      {/* Main Content */}
      <ContentArea>
        <Outlet />
      </ContentArea>

      {/* Bottom Navigation */}
      <StyledBottomNavigation
        value={getBottomNavValue()}
        onChange={handleBottomNavChange}
        showLabels
      >
        <BottomNavigationAction
          label={t('home')}
          icon={<HomeOutlined />}
        />
        <BottomNavigationAction
          label={t('sessions')}
          icon={<EventOutlined />}
        />
        <BottomNavigationAction
          label={t('resources')}
          icon={<LibraryBooksOutlined />}
        />
        <BottomNavigationAction
          label={t('profile')}
          icon={<PersonOutlined />}
        />
      </StyledBottomNavigation>

      {/* Notification Snackbar */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={hideSnackbar}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert
          onClose={hideSnackbar}
          severity={snackbar.severity}
          variant="filled"
          sx={{ width: '100%' }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </MainContainer>
  );
}

export default MobileLayout; 