import React, { useState } from 'react';
import { Outlet, useLocation, useNavigate } from 'react-router-dom';
import {
  Box,
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  ListItemButton,
  Divider,
  Avatar,
  Menu,
  MenuItem,
  Chip,
  Badge,
  Button,
  useMediaQuery,
  Snackbar,
  Alert
} from '@mui/material';
import {
  MenuOutlined,
  DashboardOutlined,
  EventOutlined,
  PeopleOutlined,
  SpaceBarOutlined,
  NotificationsOutlined,
  PersonOutlined,
  LogoutOutlined,
  HomeOutlined,
  PhoneAndroidOutlined
} from '@mui/icons-material';
import { styled, useTheme } from '@mui/material/styles';
// import { useTranslation } from 'react-i18next'; // Reserved for internationalization
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useNotification } from '../../contexts/NotificationContext';

const drawerWidth = 280;

const MainContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  minHeight: '100vh',
  backgroundColor: theme.palette.background.default,
}));

const StyledAppBar = styled(AppBar, {
  shouldForwardProp: (prop) => prop !== 'open',
})(({ theme, open }) => ({
  zIndex: theme.zIndex.drawer + 1,
  transition: theme.transitions.create(['width', 'margin'], {
    easing: theme.transitions.easing.sharp,
    duration: theme.transitions.duration.leavingScreen,
  }),
  ...(open && {
    marginLeft: drawerWidth,
    width: `calc(100% - ${drawerWidth}px)`,
    transition: theme.transitions.create(['width', 'margin'], {
      easing: theme.transitions.easing.sharp,
      duration: theme.transitions.duration.enteringScreen,
    }),
  }),
}));

const StyledDrawer = styled(Drawer)(({ theme }) => ({
  width: drawerWidth,
  flexShrink: 0,
  whiteSpace: 'nowrap',
  boxSizing: 'border-box',
  '& .MuiDrawer-paper': {
    width: drawerWidth,
    boxSizing: 'border-box',
  },
}));

const ContentArea = styled(Box)(({ theme }) => ({
  flexGrow: 1,
  padding: theme.spacing(3),
  marginTop: theme.spacing(8), // Height of AppBar
  minHeight: `calc(100vh - ${theme.spacing(8)})`,
}));

const UserSection = styled(Box)(({ theme }) => ({
  padding: theme.spacing(2),
  borderBottom: `1px solid ${theme.palette.divider}`,
}));

function AdminLayout() {
  // const { t } = useTranslation(); // Reserved for internationalization
  const { user, logout, hasRole } = useAuth();
  const { snackbar, hideSnackbar, unreadCount } = useNotification();
  const location = useLocation();
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  const [drawerOpen, setDrawerOpen] = useState(!isMobile);
  const [anchorEl, setAnchorEl] = useState(null);

  const handleDrawerToggle = () => {
    setDrawerOpen(!drawerOpen);
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    logout();
    handleMenuClose();
  };

  const getUserInitials = () => {
    if (!user) return 'U';
    return `${user.firstName?.charAt(0) || ''}${user.lastName?.charAt(0) || ''}`.toUpperCase();
  };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/admin' || path === '/admin/') return 'Dashboard';
    if (path.includes('/admin/sessions')) return 'Session Management';
    if (path.includes('/admin/users')) return 'User Management';
    if (path.includes('/admin/spaces')) return 'Space Management';
    return 'Admin Panel';
  };

  const navigationItems = [
    {
      text: 'Dashboard',
      icon: <DashboardOutlined />,
      path: '/admin',
      roles: ['TEACHER', 'SYS_ADMIN']
    },
    {
      text: 'Sessions',
      icon: <EventOutlined />,
      path: '/admin/sessions',
      roles: ['TEACHER', 'SYS_ADMIN']
    },
    {
      text: 'Users',
      icon: <PeopleOutlined />,
      path: '/admin/users',
      roles: ['SYS_ADMIN', 'TEACHER']
    },
    {
      text: 'Spaces',
      icon: <SpaceBarOutlined />,
      path: '/admin/spaces',
      roles: ['TEACHER', 'SYS_ADMIN']
    }
  ];

  const filteredNavItems = navigationItems.filter(item =>
    item.roles.some(role => hasRole(role))
  );

  const drawerContent = (
    <Box>
      {/* User Info Section */}
      <UserSection>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
          <Avatar sx={{ mr: 2, bgcolor: 'primary.main' }}>
            {getUserInitials()}
          </Avatar>
          <Box sx={{ flexGrow: 1 }}>
            <Typography variant="subtitle1" noWrap>
              {user?.firstName} {user?.lastName}
            </Typography>
            <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap' }}>
              {user?.roles?.map(role => (
                <Chip
                  key={role}
                  label={role}
                  size="small"
                  variant="outlined"
                  sx={{ fontSize: '0.7rem', height: '20px' }}
                />
              ))}
            </Box>
          </Box>
        </Box>
        
        <Button
          component={Link}
          to="/"
          variant="outlined"
          size="small"
          startIcon={<PhoneAndroidOutlined />}
          fullWidth
          sx={{ mt: 1 }}
        >
          Mobile App
        </Button>
      </UserSection>

      {/* Navigation Menu */}
      <List>
        {filteredNavItems.map((item) => (
          <ListItem key={item.text} disablePadding>
            <ListItemButton
              component={Link}
              to={item.path}
              selected={location.pathname === item.path}
              sx={{
                '&.Mui-selected': {
                  backgroundColor: 'primary.main',
                  color: 'primary.contrastText',
                  '&:hover': {
                    backgroundColor: 'primary.dark',
                  },
                  '& .MuiListItemIcon-root': {
                    color: 'primary.contrastText',
                  },
                },
              }}
            >
              <ListItemIcon>
                {item.text === 'Dashboard' && location.pathname.includes('/admin') && unreadCount > 0 ? (
                  <Badge badgeContent={unreadCount} color="error">
                    {item.icon}
                  </Badge>
                ) : (
                  item.icon
                )}
              </ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItemButton>
          </ListItem>
        ))}
      </List>

      <Divider sx={{ my: 2 }} />

      {/* Quick Actions */}
      <List>
        <ListItem disablePadding>
          <ListItemButton onClick={() => navigate('/notifications')}>
            <ListItemIcon>
              <Badge badgeContent={unreadCount} color="error">
                <NotificationsOutlined />
              </Badge>
            </ListItemIcon>
            <ListItemText primary="Notifications" />
          </ListItemButton>
        </ListItem>
        <ListItem disablePadding>
          <ListItemButton component={Link} to="/profile">
            <ListItemIcon><PersonOutlined /></ListItemIcon>
            <ListItemText primary="Profile" />
          </ListItemButton>
        </ListItem>
      </List>
    </Box>
  );

  return (
    <MainContainer>
      {/* App Bar */}
      <StyledAppBar position="fixed" open={drawerOpen && !isMobile}>
        <Toolbar>
          <IconButton
            color="inherit"
            aria-label="open drawer"
            onClick={handleDrawerToggle}
            edge="start"
            sx={{ mr: 2 }}
          >
            <MenuOutlined />
          </IconButton>

          <Typography
            variant="h6"
            noWrap
            component="div"
            sx={{
              flexGrow: 1,
              fontFamily: '"Noto Serif", serif',
              fontWeight: 600
            }}
          >
            {getPageTitle()}
          </Typography>

          <IconButton
            color="inherit"
            onClick={() => navigate('/notifications')}
            sx={{ mr: 1 }}
          >
            <Badge badgeContent={unreadCount} color="error">
              <NotificationsOutlined />
            </Badge>
          </IconButton>

          <IconButton
            color="inherit"
            onClick={handleMenuOpen}
            size="small"
          >
            <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.dark' }}>
              {getUserInitials()}
            </Avatar>
          </IconButton>
        </Toolbar>
      </StyledAppBar>

      {/* User Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
        transformOrigin={{ horizontal: 'right', vertical: 'top' }}
        anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
      >
        <MenuItem disabled>
          <Typography variant="body2" color="textSecondary">
            {user?.firstName} {user?.lastName}
          </Typography>
        </MenuItem>
        <MenuItem disabled>
          <Typography variant="caption" color="textSecondary">
            {user?.roles?.join(', ')}
          </Typography>
        </MenuItem>
        <Divider />
        <MenuItem onClick={() => { navigate('/profile'); handleMenuClose(); }}>
          <PersonOutlined sx={{ mr: 1 }} />
          Profile
        </MenuItem>
        <MenuItem onClick={() => { navigate('/'); handleMenuClose(); }}>
          <HomeOutlined sx={{ mr: 1 }} />
          Mobile App
        </MenuItem>
        <MenuItem onClick={handleLogout}>
          <LogoutOutlined sx={{ mr: 1 }} />
          Logout
        </MenuItem>
      </Menu>

      {/* Navigation Drawer */}
      <StyledDrawer
        variant={isMobile ? 'temporary' : 'persistent'}
        open={drawerOpen}
        onClose={isMobile ? handleDrawerToggle : undefined}
        ModalProps={{
          keepMounted: true, // Better open performance on mobile.
        }}
      >
        <Toolbar />
        {drawerContent}
      </StyledDrawer>

      {/* Main Content */}
      <ContentArea>
        <Outlet />
      </ContentArea>

      {/* Notification Snackbar */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={hideSnackbar}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert
          onClose={hideSnackbar}
          severity={snackbar.severity}
          variant="filled"
          sx={{ width: '100%' }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </MainContainer>
  );
}

export default AdminLayout; 