import React, { useState } from 'react';
import {
  Container,
  Box,
  Typography,
  TextField,
  Button,
  Card,
  CardContent,
  Grid,
  Chip,
  InputAdornment,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Avatar,
  Alert,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Tabs,
  Tab
} from '@mui/material';
import {
  Search,
  Event,
  Schedule,
  Person,
  FilterList,
  AccessTime,
  LocationOn,
  CheckCircle,
  Add,
  Bookmark,
  List as ListIcon
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';
import { 
  mockSessions, 
  getUserById, 
  getUserSessions, 
  getUserSessionBookmarks,
  getUserSpaces,
  currentUser
} from '../../data/mockData';

const SessionsPage = () => {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [filterTeacher, setFilterTeacher] = useState('');
  const [tabValue, setTabValue] = useState(0);
  const [registrationDialog, setRegistrationDialog] = useState({ open: false, session: null });

  // Get user's registered sessions
  const userSessions = getUserSessions(currentUser.userID);
  const registeredSessionIds = userSessions.map(s => s.sessionID);
  
  // Get user's bookmarked sessions
  const userBookmarks = getUserSessionBookmarks(currentUser.userID);
  const bookmarkedSessionIds = userBookmarks.map(b => b.sessionID);
  
  // Get user's spaces to filter available sessions
  const userSpaces = getUserSpaces(currentUser.userID);
  const userSpaceIds = userSpaces.map(s => s.spaceID);

  // Debug logging
  console.log('Current user:', currentUser.userID);
  console.log('User spaces:', userSpaces);
  console.log('User space IDs:', userSpaceIds);
  console.log('Registered sessions:', registeredSessionIds);
  console.log('Bookmarked sessions:', bookmarkedSessionIds);

  // Filter sessions based on search and filters
  const filteredSessions = mockSessions.filter(session => {
    const teacher = getUserById(session.teacherID);
    const teacherName = `${teacher?.firstName} ${teacher?.lastName}`.toLowerCase();
    const matchesSearch = session.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         session.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         teacherName.includes(searchQuery.toLowerCase());
    const matchesTeacher = !filterTeacher || session.teacherID === filterTeacher;
    
    return matchesSearch && matchesTeacher;
  });

  // Separate sessions by categories - TASK 2 reorganization
  const registeredSessions = filteredSessions.filter(session => 
    registeredSessionIds.includes(session.sessionID)
  );
  
  const bookmarkedSessions = filteredSessions.filter(session => 
    bookmarkedSessionIds.includes(session.sessionID) && !registeredSessionIds.includes(session.sessionID)
  );
  
  const availableSessions = filteredSessions.filter(session => {
    const isUpcoming = new Date(session.dateTime) > new Date();
    const isNotRegistered = !registeredSessionIds.includes(session.sessionID);
    const isNotBookmarked = !bookmarkedSessionIds.includes(session.sessionID);
    const isInUserSpace = userSpaceIds.includes(session.spaceID);
    
    // Debug logging for available sessions
    if (isUpcoming && isNotRegistered && isNotBookmarked && isInUserSpace) {
      console.log('Available session:', session.title, 'Space:', session.spaceID);
    }
    
    return isUpcoming && isNotRegistered && isNotBookmarked && isInUserSpace;
  });

  const formatSessionTime = (dateTime, timezone) => {
    const date = new Date(dateTime);
    return {
      date: format(date, 'MMM dd, yyyy'),
      time: format(date, 'HH:mm'),
      day: format(date, 'EEEE')
    };
  };

  const handleRegister = (session) => {
    setRegistrationDialog({ open: true, session });
  };

  const confirmRegistration = () => {
    // In a real app, this would make an API call
    console.log('Registering for session:', registrationDialog.session.sessionID);
    setRegistrationDialog({ open: false, session: null });
    
    // Show success message (in real app, would update state)
    alert('Successfully registered for session! You will receive a reminder notification.');
  };

  const getTeachers = () => {
    const teacherIds = [...new Set(mockSessions.map(s => s.teacherID))];
    return teacherIds.map(id => getUserById(id)).filter(Boolean);
  };

  const SessionCard = ({ session, isRegistered = false, isBookmarked = false }) => {
    const teacher = getUserById(session.teacherID);
    const host = getUserById(session.hostID);
    const timeInfo = formatSessionTime(session.dateTime, session.timezone);
    const isUpcoming = new Date(session.dateTime) > new Date();

    return (
      <Card sx={{ mb: 2, border: isRegistered ? '2px solid #4caf50' : 'none' }}>
        <CardContent>
          {/* Header */}
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
            <Box sx={{ flex: 1 }}>
              <Typography variant="h6" sx={{ fontWeight: 600, mb: 1 }}>
                {session.title}
              </Typography>
              
              {/* Status */}
              <Box sx={{ display: 'flex', gap: 1, mb: 1 }}>
                {isRegistered && (
                  <Chip 
                    icon={<CheckCircle />}
                    label="Registered" 
                    color="success" 
                    size="small"
                  />
                )}
                {isBookmarked && (
                  <Chip 
                    icon={<Bookmark />}
                    label="Bookmarked" 
                    color="primary" 
                    size="small"
                  />
                )}
              </Box>
            </Box>

            {/* Action Button */}
            <Box>
              {isRegistered ? (
                <Button
                  variant="outlined"
                  onClick={() => navigate(`/sessions/${session.sessionID}`)}
                  startIcon={<Event />}
                >
                  View Details
                </Button>
              ) : (
                <Button
                  variant="contained"
                  onClick={() => handleRegister(session)}
                  startIcon={<Add />}
                  disabled={!isUpcoming}
                >
                  {isUpcoming ? 'Register' : 'Past Session'}
                </Button>
              )}
            </Box>
          </Box>

          {/* Session Info */}
          <Grid container spacing={2} sx={{ mb: 2 }}>
            <Grid item xs={12} sm={6}>
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                <Schedule sx={{ mr: 1, color: 'primary.main' }} />
                <Box>
                  <Typography variant="body2" sx={{ fontWeight: 500 }}>
                    {timeInfo.day}, {timeInfo.date}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {timeInfo.time} • {session.duration} minutes
                  </Typography>
                </Box>
              </Box>
            </Grid>

            <Grid item xs={12} sm={6}>
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                <Person sx={{ mr: 1, color: 'primary.main' }} />
                <Box>
                  <Typography variant="body2" sx={{ fontWeight: 500 }}>
                    Teacher: {teacher?.firstName} {teacher?.lastName}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    Host: {host?.firstName} {host?.lastName}
                  </Typography>
                </Box>
              </Box>
            </Grid>
          </Grid>

          {/* Description */}
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2, lineHeight: 1.6 }}>
            {session.description}
          </Typography>

          {/* Prerequisites */}
          {session.prerequisites && (
            <Alert severity="info" sx={{ mb: 2 }}>
              <Typography variant="body2">
                <strong>Prerequisites:</strong> {session.prerequisites}
              </Typography>
            </Alert>
          )}

          {/* Additional Info */}
          <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
            <Chip 
              label={`Capacity: ${session.capacity} participants`}
              size="small"
              variant="outlined"
            />
            <Chip 
              label={session.timezone}
              size="small"
              variant="outlined"
              icon={<LocationOn />}
            />
            <Chip 
              label={session.status}
              size="small"
              color={session.status === 'SCHEDULED' ? 'success' : 'default'}
            />
          </Box>
        </CardContent>
      </Card>
    );
  };

  return (
    <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
      {/* Header */}
      <Box sx={{ mb: 3 }}>
        <Typography variant="h4" sx={{ fontWeight: 600, mb: 1 }}>
          Buddhist Learning Sessions
        </Typography>
        <Typography variant="body1" color="text.secondary">
          Discover and join listening sessions with experienced teachers
        </Typography>
      </Box>

      {/* Search and Filters */}
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                placeholder="Search sessions, teachers, or topics..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Search />
                    </InputAdornment>
                  ),
                }}
              />
            </Grid>

            <Grid item xs={12} md={4}>
              <FormControl fullWidth>
                <InputLabel>Filter by Teacher</InputLabel>
                <Select
                  value={filterTeacher}
                  label="Filter by Teacher"
                  onChange={(e) => setFilterTeacher(e.target.value)}
                >
                  <MenuItem value="">All Teachers</MenuItem>
                  {getTeachers().map((teacher) => (
                    <MenuItem key={teacher.userID} value={teacher.userID}>
                      {teacher.firstName} {teacher.lastName}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid item xs={12} md={2}>
              <Button
                fullWidth
                variant="outlined"
                startIcon={<FilterList />}
                onClick={() => {
                  setSearchQuery('');
                  setFilterTeacher('');
                }}
              >
                Clear
              </Button>
            </Grid>
          </Grid>
        </CardContent>
      </Card>

      {/* Tabs - TASK 2: Reorganized order */}
      <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}>
        <Tabs value={tabValue} onChange={(e, newValue) => setTabValue(newValue)}>
          <Tab 
            label={`My Registered Sessions (${registeredSessions.length})`}
            icon={<CheckCircle />}
          />
          <Tab 
            label={`Bookmarks (${bookmarkedSessions.length})`}
            icon={<Bookmark />}
          />
          <Tab 
            label={`Available Sessions (${availableSessions.length})`}
            icon={<Event />}
          />
        </Tabs>
      </Box>

      {/* Session Lists - TASK 2: Reorganized sections */}
      {/* Tab 0: My Registered Sessions */}
      {tabValue === 0 && (
        <Box>
          {registeredSessions.length === 0 ? (
            <Card>
              <CardContent sx={{ textAlign: 'center', py: 6 }}>
                <CheckCircle sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
                <Typography variant="h6" color="text.secondary" sx={{ mb: 1 }}>
                  No registered sessions
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                  Register for sessions to start your learning journey.
                </Typography>
                <Button 
                  variant="contained" 
                  onClick={() => setTabValue(2)}
                  startIcon={<Event />}
                >
                  Browse Available Sessions
                </Button>
              </CardContent>
            </Card>
          ) : (
            registeredSessions.map((session) => (
              <SessionCard key={session.sessionID} session={session} isRegistered={true} />
            ))
          )}
        </Box>
      )}

      {/* Tab 1: Bookmarked Sessions */}
      {tabValue === 1 && (
        <Box>
          {bookmarkedSessions.length === 0 ? (
            <Card>
              <CardContent sx={{ textAlign: 'center', py: 6 }}>
                <Bookmark sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
                <Typography variant="h6" color="text.secondary" sx={{ mb: 1 }}>
                  No bookmarked sessions
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                  Bookmark sessions you're interested in for easy access later.
                </Typography>
                <Button 
                  variant="contained" 
                  onClick={() => setTabValue(2)}
                  startIcon={<Event />}
                >
                  Browse Available Sessions
                </Button>
              </CardContent>
            </Card>
          ) : (
            bookmarkedSessions.map((session) => (
              <SessionCard key={session.sessionID} session={session} isBookmarked={true} />
            ))
          )}
        </Box>
      )}

      {/* Tab 2: Available Sessions */}
      {tabValue === 2 && (
        <Box>
          {availableSessions.length === 0 ? (
            <Card>
              <CardContent sx={{ textAlign: 'center', py: 6 }}>
                <Event sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
                <Typography variant="h6" color="text.secondary" sx={{ mb: 1 }}>
                  No available sessions found
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Try adjusting your search criteria or check back later for new sessions.
                </Typography>
              </CardContent>
            </Card>
          ) : (
            availableSessions.map((session) => (
              <SessionCard key={session.sessionID} session={session} />
            ))
          )}
        </Box>
      )}

      {/* Registration Confirmation Dialog */}
      <Dialog 
        open={registrationDialog.open} 
        onClose={() => setRegistrationDialog({ open: false, session: null })}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>Confirm Session Registration</DialogTitle>
        <DialogContent>
          {registrationDialog.session && (
            <Box>
              <Typography variant="h6" sx={{ mb: 2 }}>
                {registrationDialog.session.title}
              </Typography>
              
              <List disablePadding>
                <ListItem disablePadding>
                  <ListItemAvatar>
                    <Avatar>
                      <Schedule />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Session Date & Time"
                    secondary={(() => {
                      const timeInfo = formatSessionTime(
                        registrationDialog.session.dateTime, 
                        registrationDialog.session.timezone
                      );
                      return `${timeInfo.day}, ${timeInfo.date} at ${timeInfo.time}`;
                    })()}
                  />
                </ListItem>

                <ListItem disablePadding>
                  <ListItemAvatar>
                    <Avatar>
                      <Person />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Teacher"
                    secondary={(() => {
                      const teacher = getUserById(registrationDialog.session.teacherID);
                      return `${teacher?.firstName} ${teacher?.lastName}`;
                    })()}
                  />
                </ListItem>

                <ListItem disablePadding>
                  <ListItemAvatar>
                    <Avatar>
                      <AccessTime />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Duration"
                    secondary={`${registrationDialog.session.duration} minutes`}
                  />
                </ListItem>
              </List>

              <Alert severity="info" sx={{ mt: 2 }}>
                You will receive reminder notifications before the session starts. 
                Meeting details will be included in the reminder.
              </Alert>
            </Box>
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRegistrationDialog({ open: false, session: null })}>
            Cancel
          </Button>
          <Button 
            onClick={confirmRegistration} 
            variant="contained"
            startIcon={<CheckCircle />}
          >
            Confirm Registration
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default SessionsPage; 