import React, { useState } from 'react';
import {
  Box,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  Avatar,
  IconButton
} from '@mui/material';
import {
  Edit as EditIcon,
  Delete as DeleteIcon,
  Block as BlockIcon,
  CheckCircle as ActiveIcon
} from '@mui/icons-material';
import { useTranslation } from 'react-i18next';
import { mockUsers } from '../../data/mockData';

export default function AdminUserManagement() {
  const { t } = useTranslation();
  const [users] = useState(mockUsers);

  const getRoleChips = (roles) => roles.map(role => (
    <Chip key={role} size="small" label={t(role)} sx={{ mr: 0.5 }} />
  ));

  const getStatusChip = (isActive) => (
    <Chip 
      size="small" 
      icon={isActive ? <ActiveIcon /> : <BlockIcon />}
      color={isActive ? 'success' : 'error'}
      label={t(isActive ? 'Active' : 'Inactive')} 
    />
  );

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h4" gutterBottom>
        {t('User Management')}
      </Typography>

      <TableContainer component={Paper}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>{t('User')}</TableCell>
              <TableCell>{t('Email')}</TableCell>
              <TableCell>{t('Roles')}</TableCell>
              <TableCell>{t('Status')}</TableCell>
              <TableCell>{t('Join Date')}</TableCell>
              <TableCell>{t('Timezone')}</TableCell>
              <TableCell align="right">{t('Actions')}</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {users.map((user) => (
              <TableRow key={user.userID}>
                <TableCell>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Avatar sx={{ mr: 2 }}>
                      {user.firstName[0]}{user.lastName[0]}
                    </Avatar>
                    <Typography variant="subtitle2">
                      {user.firstName} {user.lastName}
                    </Typography>
                  </Box>
                </TableCell>
                <TableCell>{user.email}</TableCell>
                <TableCell>{getRoleChips(user.roles)}</TableCell>
                <TableCell>{getStatusChip(user.isActive)}</TableCell>
                <TableCell>{new Date(user.createdDate).toLocaleDateString()}</TableCell>
                <TableCell>{user.timezone}</TableCell>
                <TableCell align="right">
                  <IconButton size="small">
                    <EditIcon />
                  </IconButton>
                  <IconButton size="small">
                    <DeleteIcon />
                  </IconButton>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
} 