import React, { createContext, useContext, useState, useEffect } from 'react';
import { mockUsers, mockSpaces, mockSessions } from '../data/mockData';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulate checking for existing session
    const checkExistingSession = async () => {
      try {
        const savedUserId = localStorage.getItem('currentUserId');
        if (savedUserId) {
          const existingUser = mockUsers.find(u => u.userID === savedUserId);
          if (existingUser) {
            setUser(existingUser);
          }
        }
      } catch (error) {
        console.error('Session check error:', error);
      } finally {
        setLoading(false);
      }
    };

    // Add delay to simulate real authentication check
    setTimeout(checkExistingSession, 800);
  }, []);

  const login = async (email, password) => {
    try {
      // Find user by email
      const foundUser = mockUsers.find(u => u.email === email);
      
      if (!foundUser) {
        throw new Error('User not found');
      }

      // In a real app, you'd verify the password hash
      // For demo purposes, we'll accept any password
      
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      setUser(foundUser);
      localStorage.setItem('currentUserId', foundUser.userID);
      
      return { success: true, user: foundUser };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const register = async (userData) => {
    try {
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // Check if user already exists
      const existingUser = mockUsers.find(u => u.email === userData.email);
      if (existingUser) {
        throw new Error('User already exists');
      }

      // Create new user
      const newUser = {
        userID: `user_${Date.now()}`,
        email: userData.email,
        firstName: userData.firstName,
        lastName: userData.lastName,
        roles: ['STUDENT'],
        timezone: userData.timezone || 'America/New_York',
        language: userData.language || 'en',
        country: userData.country || '',
        place: userData.place || '',
        aboutDescription: '',
        profilePhotoURL: '',
        userSettings: {
          notifications: {
            sessionReminders: true,
            announcements: true,
            quietHours: { start: '22:00', end: '07:00' }
          },
          remindBefore: 15 // minutes
        },
        createdDate: new Date().toISOString(),
        lastLoginDate: new Date().toISOString(),
        isActive: true
      };

      // In a real app, you'd save to the backend
      mockUsers.push(newUser);
      
      setUser(newUser);
      localStorage.setItem('currentUserId', newUser.userID);
      
      return { success: true, user: newUser };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('currentUserId');
  };

  const updateProfile = async (profileData) => {
    try {
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 500));
      
      const updatedUser = { ...user, ...profileData };
      setUser(updatedUser);
      
      // Update in mock data
      const userIndex = mockUsers.findIndex(u => u.userID === user.userID);
      if (userIndex !== -1) {
        mockUsers[userIndex] = updatedUser;
      }
      
      return { success: true, user: updatedUser };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const switchUserForDemo = (userId) => {
    // Special function for demo purposes to switch between different user types
    const newUser = mockUsers.find(u => u.userID === userId);
    if (newUser) {
      setUser(newUser);
      localStorage.setItem('currentUserId', newUser.userID);
    }
  };

  const hasRole = (role) => {
    return user?.roles?.includes(role) || false;
  };

  const hasAnyRole = (roles) => {
    return roles.some(role => user?.roles?.includes(role)) || false;
  };

  const getUserSpaces = () => {
    if (!user) return [];
    
    // Find spaces where user is a member
    return mockSpaces.filter(space => 
      space.members.some(member => member.userID === user.userID)
    );
  };

  const getUserSessions = () => {
    if (!user) return [];
    
    const userSpaces = getUserSpaces();
    const spaceIds = userSpaces.map(space => space.spaceID);
    
    return mockSessions.filter(session => 
      spaceIds.some(spaceId => session.spaceIDs.includes(spaceId))
    );
  };

  const getRegisteredSessions = () => {
    if (!user) return [];
    
    return mockSessions.filter(session => 
      session.registrations.some(reg => reg.userID === user.userID)
    );
  };

  const value = {
    user,
    loading,
    login,
    register,
    logout,
    updateProfile,
    switchUserForDemo,
    hasRole,
    hasAnyRole,
    getUserSpaces,
    getUserSessions,
    getRegisteredSessions
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}; 