import React, { useState } from 'react';
import {
  Container,
  Card,
  CardContent,
  Typography,
  Button,
  Box,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Alert,
  Grid,
  IconButton,
  Link,
  Paper,
  Snackbar,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField
} from '@mui/material';
import {
  ArrowBack,
  Schedule,
  Person,
  Group,
  AccessTime,
  LocationOn,
  Link as LinkIcon,
  VideoCall,
  CheckCircle,
  Notifications,
  Share,
  BookmarkBorder,
  Bookmark,
  Info,
  Launch,
  Chat,
  Close,
  List as ListIcon
} from '@mui/icons-material';
import { useNavigate, useParams } from 'react-router-dom';
import { format } from 'date-fns';
import { 
  getSessionById, 
  getUserById, 
  getUserSessions, 
  currentUser,
  isSessionBookmarked,
  addSessionBookmark,
  removeSessionBookmark,
  getUserSessionBookmarks
} from '../../data/mockData';

const SessionDetail = () => {
  const navigate = useNavigate();
  const { sessionId } = useParams();
  const [reminderSet, setReminderSet] = useState(false);
  
  // TASK 3 & 4: Share and Bookmark functionality
  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState('');
  const [bookmarkDialogOpen, setBookmarkDialogOpen] = useState(false);
  const [bookmarksListOpen, setBookmarksListOpen] = useState(false);
  
  const session = getSessionById(sessionId);
  const userSessions = getUserSessions(currentUser.userID);
  const isRegistered = userSessions.some(s => s.sessionID === sessionId);
  const isBookmarked = isSessionBookmarked(currentUser.userID, sessionId);
  const userBookmarks = getUserSessionBookmarks(currentUser.userID);

  if (!session) {
    return (
      <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
        <Card>
          <CardContent sx={{ textAlign: 'center', py: 6 }}>
            <Typography variant="h6" color="text.secondary">
              Session not found
            </Typography>
            <Button 
              variant="contained" 
              onClick={() => navigate('/sessions')}
              sx={{ mt: 2 }}
            >
              Back to Sessions
            </Button>
          </CardContent>
        </Card>
      </Container>
    );
  }

  const teacher = getUserById(session.teacherID);
  const host = getUserById(session.hostID);
  
  const formatSessionTime = (dateTime, timezone) => {
    const date = new Date(dateTime);
    return {
      date: format(date, 'EEEE, MMMM dd, yyyy'),
      time: format(date, 'HH:mm'),
      localTime: format(date, 'HH:mm zzz')
    };
  };

  const timeInfo = formatSessionTime(session.dateTime, session.timezone);
  const isUpcoming = new Date(session.dateTime) > new Date();
  const timeUntilSession = new Date(session.dateTime) - new Date();
  const daysUntil = Math.ceil(timeUntilSession / (1000 * 60 * 60 * 24));

  const handleJoinSession = () => {
    window.open(session.meetingRoomURL, '_blank');
  };

  const handleSetReminder = () => {
    setReminderSet(true);
    // In a real app, this would set a reminder notification
  };

  // TASK 3: Share Session functionality
  const handleShareSession = async () => {
    const teacher = getUserById(session.teacherID);
    const host = getUserById(session.hostID);
    const timeInfo = formatSessionTime(session.dateTime, session.timezone);
    
    const shareText = `${session.title}

Teacher: ${teacher?.firstName} ${teacher?.lastName}
Host: ${host?.firstName} ${host?.lastName}
Time: ${timeInfo.date} at ${timeInfo.time} (${session.timezone})

Chat Room: ${session.chatRoomURL || 'Not available'}
Meeting Room: ${session.meetingRoomURL || 'Not available'}

Join us for this Buddhist learning session!`;

    try {
      await navigator.clipboard.writeText(shareText);
      setSnackbarMessage('Session details copied to clipboard!');
      setSnackbarOpen(true);
    } catch (err) {
      // Fallback for browsers that don't support clipboard API
      const textArea = document.createElement('textarea');
      textArea.value = shareText;
      document.body.appendChild(textArea);
      textArea.select();
      document.execCommand('copy');
      document.body.removeChild(textArea);
      setSnackbarMessage('Session details copied to clipboard!');
      setSnackbarOpen(true);
    }
  };

  // TASK 4: Bookmark functionality
  const handleBookmarkToggle = () => {
    if (isBookmarked) {
      if (removeSessionBookmark(currentUser.userID, sessionId)) {
        setSnackbarMessage('Session removed from bookmarks');
        setSnackbarOpen(true);
      }
    } else {
      if (addSessionBookmark(currentUser.userID, sessionId, '')) {
        setSnackbarMessage('Session bookmarked successfully!');
        setSnackbarOpen(true);
      }
    }
  };

  const handleViewBookmarks = () => {
    setBookmarksListOpen(true);
  };

  const handleNavigateToBookmark = (bookmarkedSessionId) => {
    setBookmarksListOpen(false);
    if (bookmarkedSessionId !== sessionId) {
      navigate(`/sessions/${bookmarkedSessionId}`);
    }
  };

  return (
    <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
      {/* Header */}
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
        <IconButton onClick={() => navigate('/sessions')} sx={{ mr: 2 }}>
          <ArrowBack />
        </IconButton>
        <Typography variant="h4" sx={{ fontWeight: 600 }}>
          Session Details
        </Typography>
      </Box>



      <Grid container spacing={3}>
        {/* Main Content */}
        <Grid item xs={12} md={8}>
          
          {/* Session Info Card */}
          <Card sx={{ mb: 3 }}>
            <CardContent>
              
              {/* Title and Status */}
              <Box sx={{ mb: 3 }}>
                <Typography variant="h5" sx={{ fontWeight: 600, mb: 2 }}>
                  {session.title}
                </Typography>
                
                <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
                  {isRegistered && (
                    <Chip 
                      icon={<CheckCircle />}
                      label="You're Registered" 
                      color="success"
                    />
                  )}
                  <Chip 
                    label={session.status}
                    color={session.status === 'SCHEDULED' ? 'primary' : 'default'}
                  />
                  <Chip 
                    label={isUpcoming ? `${daysUntil} days until session` : 'Past Session'}
                    variant="outlined"
                  />
                </Box>
              </Box>

              {/* Session Details */}
              <List disablePadding>
                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'primary.main' }}>
                      <Schedule />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Date & Time"
                    secondary={
                      <Box>
                        <Typography variant="body2">
                          {timeInfo.date}
                        </Typography>
                        <Typography variant="body2" color="primary">
                          {timeInfo.time} ({session.timezone})
                        </Typography>
                        
                        {/* TASK 2: Meeting Access Links in Date & Time section */}
                        {session.sessionFormat && (session.sessionFormat === 'ONLINE' || session.sessionFormat === 'HYBRID') && (
                          <Box sx={{ mt: 2 }}>
                            <Typography variant="body2" sx={{ fontWeight: 600, mb: 1 }}>
                              Session Access:
                            </Typography>
                            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                              {session.meetingRoomURL && (
                                <Button
                                  variant="contained"
                                  size="small"
                                  startIcon={<VideoCall />}
                                  endIcon={<Launch />}
                                  href={session.meetingRoomURL}
                                  target="_blank"
                                  rel="noopener noreferrer"
                                  sx={{ 
                                    alignSelf: 'flex-start',
                                    fontSize: '0.75rem',
                                    py: 0.5,
                                    px: 1.5
                                  }}
                                >
                                  Join Meeting Room
                                </Button>
                              )}
                              
                              {session.chatRoomURL && (
                                <Button
                                  variant="outlined"
                                  size="small"
                                  startIcon={<Chat />}
                                  endIcon={<Launch />}
                                  href={session.chatRoomURL}
                                  target="_blank"
                                  rel="noopener noreferrer"
                                  sx={{ 
                                    alignSelf: 'flex-start',
                                    fontSize: '0.75rem',
                                    py: 0.5,
                                    px: 1.5
                                  }}
                                >
                                  Join Chat Room
                                </Button>
                              )}
                            </Box>
                          </Box>
                        )}
                      </Box>
                    }
                  />
                </ListItem>

                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'secondary.main' }}>
                      <Person />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Teacher"
                    secondary={
                      <Box>
                        <Typography variant="body2" sx={{ fontWeight: 500 }}>
                          {teacher?.firstName} {teacher?.lastName}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {teacher?.aboutDescription}
                        </Typography>
                      </Box>
                    }
                  />
                </ListItem>

                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'info.main' }}>
                      <Group />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Session Host"
                    secondary={`${host?.firstName} ${host?.lastName}`}
                  />
                </ListItem>

                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'warning.main' }}>
                      <AccessTime />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Duration"
                    secondary={`${session.duration} minutes`}
                  />
                </ListItem>

                {/* TASK 2: Location Field */}
                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'error.main' }}>
                      <LocationOn />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Location"
                    secondary={
                      <Box>
                        <Typography variant="body2" sx={{ fontWeight: 500 }}>
                          {session.location || 'Not specified'}
                        </Typography>
                        <Chip 
                          label={session.sessionFormat || 'Online'}
                          size="small"
                          color={
                            session.sessionFormat === 'ONLINE' ? 'primary' : 
                            session.sessionFormat === 'OFFLINE' ? 'secondary' : 
                            session.sessionFormat === 'HYBRID' ? 'info' : 'default'
                          }
                          sx={{ mt: 0.5 }}
                        />
                      </Box>
                    }
                  />
                </ListItem>

                <ListItem disablePadding sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Avatar sx={{ bgcolor: 'success.main' }}>
                      <Schedule />
                    </Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary="Timezone"
                    secondary={session.timezone}
                  />
                </ListItem>
              </List>
            </CardContent>
          </Card>

          {/* Description */}
          <Card sx={{ mb: 3 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: 600, mb: 2 }}>
                Session Description
              </Typography>
              <Typography variant="body1" sx={{ lineHeight: 1.7 }}>
                {session.description}
              </Typography>
            </CardContent>
          </Card>

          {/* Prerequisites */}
          {session.prerequisites && (
            <Card sx={{ mb: 3 }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Info sx={{ mr: 1, color: 'info.main' }} />
                  <Typography variant="h6" sx={{ fontWeight: 600 }}>
                    Prerequisites
                  </Typography>
                </Box>
                <Alert severity="info">
                  {session.prerequisites}
                </Alert>
              </CardContent>
            </Card>
          )}

          {/* Materials and Resources */}
          {session.materialLinks && session.materialLinks.length > 0 && (
            <Card sx={{ mb: 3 }}>
              <CardContent>
                <Typography variant="h6" sx={{ fontWeight: 600, mb: 2 }}>
                  Session Materials
                </Typography>
                <List disablePadding>
                  {session.materialLinks.map((link, index) => (
                    <ListItem key={index} disablePadding sx={{ py: 0.5 }}>
                      <ListItemAvatar>
                        <Avatar sx={{ bgcolor: 'grey.100', color: 'grey.600', width: 32, height: 32 }}>
                          <LinkIcon sx={{ fontSize: 16 }} />
                        </Avatar>
                      </ListItemAvatar>
                      <ListItemText
                        primary={
                          <Link 
                            href={link} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            sx={{ textDecoration: 'none' }}
                          >
                            Session Materials #{index + 1}
                          </Link>
                        }
                        secondary="Click to access preparation materials"
                      />
                    </ListItem>
                  ))}
                </List>
              </CardContent>
            </Card>
          )}
        </Grid>

        {/* Sidebar */}
        <Grid item xs={12} md={4}>
          
          {/* Action Panel */}
          <Card sx={{ mb: 3, position: 'sticky', top: 20 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: 600, mb: 2 }}>
                Session Actions
              </Typography>

              {/* Join Session Button */}
              {isRegistered && isUpcoming && (
                <Button
                  fullWidth
                  variant="contained"
                  size="large"
                  startIcon={<VideoCall />}
                  onClick={handleJoinSession}
                  sx={{ mb: 2 }}
                >
                  Join Session
                </Button>
              )}

              {/* Registration Button */}
              {!isRegistered && isUpcoming && (
                <Button
                  fullWidth
                  variant="contained"
                  size="large"
                  startIcon={<CheckCircle />}
                  sx={{ mb: 2 }}
                >
                  Register for Session
                </Button>
              )}

              {/* Set Reminder */}
              {isRegistered && isUpcoming && (
                <Button
                  fullWidth
                  variant="outlined"
                  startIcon={<Notifications />}
                  onClick={handleSetReminder}
                  disabled={reminderSet}
                  sx={{ mb: 2 }}
                >
                  {reminderSet ? 'Reminder Set' : 'Set Personal Reminder'}
                </Button>
              )}

              {/* Share Session - TASK 3 */}
              <Button
                fullWidth
                variant="outlined"
                startIcon={<Share />}
                onClick={handleShareSession}
                sx={{ mb: 2 }}
              >
                Share Session
              </Button>

              {/* Bookmark - TASK 4 */}
              <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                <Button
                  fullWidth
                  variant="outlined"
                  startIcon={isBookmarked ? <Bookmark /> : <BookmarkBorder />}
                  onClick={handleBookmarkToggle}
                  color={isBookmarked ? "primary" : "inherit"}
                >
                  {isBookmarked ? 'Bookmarked' : 'Bookmark'}
                </Button>
                <IconButton
                  onClick={handleViewBookmarks}
                  title="View All Bookmarks"
                  sx={{ border: '1px solid', borderColor: 'divider' }}
                >
                  <ListIcon />
                </IconButton>
              </Box>
            </CardContent>
          </Card>

          {/* Session Info Summary */}
          <Card sx={{ mb: 3 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: 600, mb: 2 }}>
                Quick Info
              </Typography>
              
              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                <Typography variant="body2" color="text.secondary">
                  Capacity:
                </Typography>
                <Typography variant="body2" sx={{ fontWeight: 500 }}>
                  {session.capacity} participants
                </Typography>
              </Box>

              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                <Typography variant="body2" color="text.secondary">
                  Language:
                </Typography>
                <Typography variant="body2" sx={{ fontWeight: 500 }}>
                  English
                </Typography>
              </Box>

              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                <Typography variant="body2" color="text.secondary">
                  Level:
                </Typography>
                <Typography variant="body2" sx={{ fontWeight: 500 }}>
                  {session.prerequisites ? 'Intermediate' : 'Beginner Friendly'}
                </Typography>
              </Box>

              <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                <Typography variant="body2" color="text.secondary">
                  Format:
                </Typography>
                <Typography variant="body2" sx={{ fontWeight: 500 }}>
                  {session.sessionFormat === 'ONLINE' ? 'Online Live Session' : 
                   session.sessionFormat === 'OFFLINE' ? 'In-Person Session' : 
                   session.sessionFormat === 'HYBRID' ? 'Hybrid Session' : 'Live Session'}
                </Typography>
              </Box>
            </CardContent>
          </Card>

          {/* Meeting Info (for registered users) - Show location for offline/hybrid sessions */}
          {isRegistered && (
            <Paper sx={{ p: 2, bgcolor: '#f3e5f5', border: '1px solid #e1bee7' }}>
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                <LocationOn sx={{ mr: 1, color: 'secondary.main' }} />
                <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
                  Session Access Information
                </Typography>
              </Box>
              
              {session.sessionFormat === 'OFFLINE' && (
                <Box>
                  <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    This is an in-person session. Please arrive 15 minutes early.
                  </Typography>
                  
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                    <LocationOn sx={{ fontSize: 16, mr: 1, color: 'error.main' }} />
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>
                      Location: {session.location}
                    </Typography>
                  </Box>
                </Box>
              )}
              
              {session.sessionFormat === 'HYBRID' && (
                <Box>
                  <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    Hybrid session - Join online or attend in-person.
                  </Typography>
                  
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                    <LocationOn sx={{ fontSize: 16, mr: 1, color: 'error.main' }} />
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>
                      Location: {session.location}
                    </Typography>
                  </Box>
                </Box>
              )}
              
              {session.sessionFormat === 'ONLINE' && (
                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                  Online session - Links available above and will be sent 30 minutes before start.
                </Typography>
              )}
            </Paper>
          )}
        </Grid>
      </Grid>

      {/* TASK 4: Bookmarks List Dialog */}
      <Dialog open={bookmarksListOpen} onClose={() => setBookmarksListOpen(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Typography variant="h6">My Bookmarked Sessions</Typography>
            <IconButton onClick={() => setBookmarksListOpen(false)}>
              <Close />
            </IconButton>
          </Box>
        </DialogTitle>
        <DialogContent>
          {userBookmarks.length === 0 ? (
            <Box sx={{ textAlign: 'center', py: 4 }}>
              <Typography variant="body1" color="text.secondary">
                No bookmarked sessions yet
              </Typography>
              <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                Bookmark sessions you want to remember or easily access later
              </Typography>
            </Box>
          ) : (
            <List>
              {userBookmarks.map((bookmark) => {
                const bookmarkSession = bookmark.session;
                const teacher = getUserById(bookmarkSession.teacherID);
                const timeInfo = formatSessionTime(bookmarkSession.dateTime, bookmarkSession.timezone);
                const isCurrent = bookmark.sessionID === sessionId;
                
                return (
                  <ListItem 
                    key={bookmark.bookmarkID}
                    sx={{
                      border: '1px solid',
                      borderColor: isCurrent ? 'primary.main' : 'divider',
                      borderRadius: 2,
                      mb: 2,
                      bgcolor: isCurrent ? 'primary.50' : 'background.paper'
                    }}
                  >
                    <ListItemText
                      primary={
                        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                            {bookmarkSession.title}
                            {isCurrent && (
                              <Chip label="Current" size="small" color="primary" sx={{ ml: 1 }} />
                            )}
                          </Typography>
                          {!isCurrent && (
                            <Button
                              size="small"
                              onClick={() => handleNavigateToBookmark(bookmark.sessionID)}
                            >
                              View Details
                            </Button>
                          )}
                        </Box>
                      }
                      secondary={
                        <Box sx={{ mt: 1 }}>
                          <Typography variant="body2" color="text.secondary">
                            Teacher: {teacher?.firstName} {teacher?.lastName}
                          </Typography>
                          <Typography variant="body2" color="text.secondary">
                            {timeInfo.date} at {timeInfo.time}
                          </Typography>
                          {bookmark.notes && (
                            <Typography variant="body2" sx={{ mt: 0.5, fontStyle: 'italic' }}>
                              Note: {bookmark.notes}
                            </Typography>
                          )}
                          <Typography variant="caption" color="text.secondary">
                            Bookmarked on {format(new Date(bookmark.bookmarkedDate), 'MMM dd, yyyy')}
                          </Typography>
                        </Box>
                      }
                    />
                  </ListItem>
                );
              })}
            </List>
          )}
        </DialogContent>
      </Dialog>

      {/* Snackbar for notifications */}
      <Snackbar
        open={snackbarOpen}
        autoHideDuration={3000}
        onClose={() => setSnackbarOpen(false)}
        message={snackbarMessage}
      />
    </Container>
  );
};

export default SessionDetail; 