import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useNotification } from './NotificationContext';
import { 
  mockSessions, 
  mockSessionReminders,
  getSessionById, 
  getUserById,
  getSpaceById,
  isUserRegisteredForSession,
  getUserSpaces,
  getRecurringSessionInstances,
  getRecurringSessionMaster,
  getSessionReminders,
  getUserSessionReminders,
  getSessionAnnouncements,
  canUserBroadcastToSession
} from '../data/mockData';

const SessionContext = createContext();

export const useSession = () => {
  const context = useContext(SessionContext);
  if (!context) {
    throw new Error('useSession must be used within a SessionProvider');
  }
  return context;
};

export const SessionProvider = ({ children }) => {
  const { user } = useAuth();
  const { showSuccess, showError, createNotification, scheduleSessionReminder } = useNotification();
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(false);

  const loadSessions = useCallback(() => {
    if (!user) {
      setSessions([]);
      return;
    }

    // Get all sessions available to user's spaces
    const userSpaces = getUserSpaces(user.userID);
    const spaceIds = userSpaces.map(space => space.spaceID);
    
    const availableSessions = mockSessions.filter(session => 
      spaceIds.includes(session.spaceID)
    );

    setSessions(availableSessions);
  }, [user]);

  useEffect(() => {
    loadSessions();
  }, [loadSessions]);

  const getAvailableSessions = () => {
    const now = new Date();
    return sessions.filter(session => 
      session.status === 'SCHEDULED' && 
      new Date(session.dateTime) > now &&
      session.sessionType !== 'RECURRING_MASTER' // Don't show master templates
    );
  };

  const getRegisteredSessions = () => {
    if (!user) return [];
    
    return sessions.filter(session => 
      session.registrations.some(reg => 
        reg.userID === user.userID && 
        ['CONFIRMED', 'ATTENDED'].includes(reg.status)
      )
    );
  };

  const getPastSessions = () => {
    const now = new Date();
    return sessions.filter(session => 
      (session.status === 'COMPLETED' || 
       (session.status === 'SCHEDULED' && new Date(session.dateTime) < now)) &&
      session.sessionType !== 'RECURRING_MASTER' // Don't show master templates
    );
  };

  // Enhanced functions for recurring sessions
  const getRecurringSeries = () => {
    const masterSessions = sessions.filter(session => session.sessionType === 'RECURRING_MASTER');
    return masterSessions.map(master => {
      const instances = getRecurringSessionInstances(master.seriesID);
      return {
        master: master,
        instances: instances,
        totalInstances: instances.length,
        completedInstances: instances.filter(inst => inst.status === 'COMPLETED').length,
        upcomingInstances: instances.filter(inst => inst.status === 'SCHEDULED' && new Date(inst.dateTime) > new Date()).length
      };
    });
  };

  const getSessionSeries = (sessionId) => {
    const session = getSessionById(sessionId);
    if (!session || !session.seriesID) return null;
    
    const master = getRecurringSessionMaster(session.seriesID);
    const instances = getRecurringSessionInstances(session.seriesID);
    
    return {
      master: master,
      instances: instances,
      currentInstance: session
    };
  };

  // Enhanced functions for session reminders
  const getSessionRemindersForUser = (sessionId = null) => {
    if (!user) return [];
    
    if (sessionId) {
      return getSessionReminders(sessionId).filter(reminder => 
        reminder.userID === user.userID || reminder.userID === null
      );
    }
    
    return getUserSessionReminders(user.userID);
  };

  const createSessionReminder = async (sessionId, reminderData) => {
    if (!user) {
      showError('Please log in to create reminders');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      // Calculate trigger date time
      const sessionDateTime = new Date(session.dateTime);
      const triggerDateTime = new Date(sessionDateTime.getTime() - (reminderData.triggerOffset * 60 * 1000));

      const newReminder = {
        reminderID: `reminder_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        sessionID: sessionId,
        userID: user.userID,
        reminderType: reminderData.reminderType || 'USER_CUSTOM',
        triggerOffset: reminderData.triggerOffset,
        triggerDateTime: triggerDateTime.toISOString(),
        status: 'PENDING',
        messageTemplate: reminderData.messageTemplate || null,
        deliveryMethods: reminderData.deliveryMethods || ['PUSH', 'IN_APP'],
        priority: reminderData.priority || 'NORMAL',
        isRecurring: session.sessionType === 'RECURRING_INSTANCE',
        customMessage: reminderData.customMessage || null,
        createdDate: new Date().toISOString(),
        sentDate: null
      };

      // Add to mock data
      mockSessionReminders.push(newReminder);

      showSuccess('Reminder created successfully!');
      return { success: true, reminder: newReminder };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const updateSessionReminder = async (reminderId, updates) => {
    if (!user) {
      showError('Please log in to update reminders');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const reminderIndex = mockSessionReminders.findIndex(r => r.reminderID === reminderId);
      if (reminderIndex === -1) {
        throw new Error('Reminder not found');
      }

      const reminder = mockSessionReminders[reminderIndex];
      if (reminder.userID !== user.userID && !user.roles.includes('SYS_ADMIN')) {
        throw new Error('Not authorized to update this reminder');
      }

      // Update the reminder
      mockSessionReminders[reminderIndex] = { ...reminder, ...updates };

      showSuccess('Reminder updated successfully!');
      return { success: true, reminder: mockSessionReminders[reminderIndex] };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const deleteSessionReminder = async (reminderId) => {
    if (!user) {
      showError('Please log in to delete reminders');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const reminderIndex = mockSessionReminders.findIndex(r => r.reminderID === reminderId);
      if (reminderIndex === -1) {
        throw new Error('Reminder not found');
      }

      const reminder = mockSessionReminders[reminderIndex];
      if (reminder.userID !== user.userID && !user.roles.includes('SYS_ADMIN')) {
        throw new Error('Not authorized to delete this reminder');
      }

      // Remove the reminder
      mockSessionReminders.splice(reminderIndex, 1);

      showSuccess('Reminder deleted successfully!');
      return { success: true };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const registerForSession = async (sessionId) => {
    if (!user) {
      showError('Please log in to register for sessions');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      // Check if already registered
      if (isUserRegisteredForSession(user.userID, sessionId)) {
        throw new Error('Already registered for this session');
      }

      // Check capacity
      if (session.registrations.length >= session.capacity) {
        throw new Error('Session is full');
      }

      // Check if session is in the future
      if (new Date(session.dateTime) <= new Date()) {
        throw new Error('Cannot register for past sessions');
      }

      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 800));

      // Add registration
      const newRegistration = {
        userID: user.userID,
        registeredDate: new Date().toISOString(),
        status: 'CONFIRMED'
      };

      session.registrations.push(newRegistration);

      // Update local state
      setSessions(prev => prev.map(s => 
        s.sessionID === sessionId ? { ...s, registrations: [...s.registrations, newRegistration] } : s
      ));

      // Create confirmation notification
      createNotification({
        type: 'NOTIFICATION',
        title: 'Registration Confirmed',
        content: `You have successfully registered for "${session.title}". We look forward to seeing you there!`,
        sessionId: sessionId,
        priority: 'NORMAL'
      });

      // Schedule reminder based on user preferences
      const reminderMinutes = user.userSettings?.remindBefore || 15;
      scheduleSessionReminder(session, reminderMinutes);

      showSuccess('Successfully registered for session!');
      
      return { success: true, registration: newRegistration };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const unregisterFromSession = async (sessionId) => {
    if (!user) {
      showError('Please log in to unregister from sessions');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      // Check if registered
      if (!isUserRegisteredForSession(user.userID, sessionId)) {
        throw new Error('Not registered for this session');
      }

      // Check if session allows unregistration (e.g., not too close to start time)
      const sessionTime = new Date(session.dateTime);
      const now = new Date();
      const hoursUntilSession = (sessionTime - now) / (1000 * 60 * 60);
      
      if (hoursUntilSession < 2) {
        throw new Error('Cannot unregister less than 2 hours before session');
      }

      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 600));

      // Remove registration
      session.registrations = session.registrations.filter(reg => reg.userID !== user.userID);

      // Update local state
      setSessions(prev => prev.map(s => 
        s.sessionID === sessionId ? { ...s, registrations: session.registrations } : s
      ));

      // Create notification
      createNotification({
        type: 'NOTIFICATION',
        title: 'Unregistered from Session',
        content: `You have been unregistered from "${session.title}".`,
        sessionId: sessionId,
        priority: 'NORMAL'
      });

      showSuccess('Successfully unregistered from session');
      
      return { success: true };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const createSession = async (sessionData) => {
    if (!user || !user.roles.includes('TEACHER')) {
      showError('Only teachers can create sessions');
      return { success: false, error: 'Unauthorized' };
    }

    try {
      setLoading(true);

      // Validate session data
      if (!sessionData.title || !sessionData.description || !sessionData.dateTime) {
        throw new Error('Please fill in all required fields');
      }

      if (new Date(sessionData.dateTime) <= new Date()) {
        throw new Error('Session must be scheduled in the future');
      }

      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 1000));

      const newSession = {
        sessionID: `session_${Date.now()}`,
        title: sessionData.title,
        description: sessionData.description,
        timezone: sessionData.timezone || user.timezone,
        dateTime: sessionData.dateTime,
        duration: sessionData.duration || 60,
        meetingRoomURL: sessionData.meetingRoomURL,
        teacherID: user.userID,
        hostID: sessionData.hostID || user.userID,
        capacity: sessionData.capacity || 25,
        spaceIDs: sessionData.spaceIDs || [],
        status: 'SCHEDULED',
        registrations: [],
        createdDate: new Date().toISOString(),
        lastModifiedDate: new Date().toISOString()
      };

      // Add to mock data
      mockSessions.push(newSession);

      // Update local state
      setSessions(prev => [...prev, newSession]);

      // Create announcement for relevant spaces
      sessionData.spaceIDs?.forEach(spaceId => {
        const space = getSpaceById(spaceId);
        if (space) {
          createNotification({
            type: 'ANNOUNCEMENT',
            title: 'New Session Available',
            content: `A new session "${newSession.title}" has been scheduled. Check it out and register if interested!`,
            sessionId: newSession.sessionID,
            spaceId: spaceId,
            priority: 'NORMAL'
          });
        }
      });

      showSuccess('Session created successfully!');
      
      return { success: true, session: newSession };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const updateSession = async (sessionId, updates) => {
    if (!user || !user.roles.includes('TEACHER')) {
      showError('Only teachers can update sessions');
      return { success: false, error: 'Unauthorized' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      if (session.teacherID !== user.userID && !user.roles.includes('SYS_ADMIN')) {
        throw new Error('You can only update your own sessions');
      }

      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 600));

      const updatedSession = {
        ...session,
        ...updates,
        lastModifiedDate: new Date().toISOString()
      };

      // Update in mock data
      const sessionIndex = mockSessions.findIndex(s => s.sessionID === sessionId);
      if (sessionIndex !== -1) {
        mockSessions[sessionIndex] = updatedSession;
      }

      // Update local state
      setSessions(prev => prev.map(s => 
        s.sessionID === sessionId ? updatedSession : s
      ));

      // Notify registered students of changes
      if (session.registrations.length > 0) {
        session.registrations.forEach(registration => {
          createNotification({
            type: 'NOTIFICATION',
            title: 'Session Updated',
            content: `The session "${session.title}" has been updated. Please check the new details.`,
            sessionId: sessionId,
            priority: 'NORMAL'
          });
        });
      }

      showSuccess('Session updated successfully!');
      
      return { success: true, session: updatedSession };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const deleteSession = async (sessionId) => {
    if (!user || !user.roles.includes('TEACHER')) {
      showError('Only teachers can delete sessions');
      return { success: false, error: 'Unauthorized' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      if (session.teacherID !== user.userID && !user.roles.includes('SYS_ADMIN')) {
        throw new Error('You can only delete your own sessions');
      }

      // Check if session has started
      if (new Date(session.dateTime) <= new Date()) {
        throw new Error('Cannot delete sessions that have already started');
      }

      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 600));

      // Notify registered students
      session.registrations.forEach(registration => {
        createNotification({
          type: 'NOTIFICATION',
          title: 'Session Cancelled',
          content: `The session "${session.title}" has been cancelled. We apologize for any inconvenience.`,
          sessionId: sessionId,
          priority: 'HIGH'
        });
      });

      // Remove from mock data
      const sessionIndex = mockSessions.findIndex(s => s.sessionID === sessionId);
      if (sessionIndex !== -1) {
        mockSessions.splice(sessionIndex, 1);
      }

      // Update local state
      setSessions(prev => prev.filter(s => s.sessionID !== sessionId));

      showSuccess('Session deleted successfully');
      
      return { success: true };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const getSessionDetails = (sessionId) => {
    const session = getSessionById(sessionId);
    if (!session) return null;

    const teacher = getUserById(session.teacherID);
    const host = getUserById(session.hostID);
    const space = getSpaceById(session.spaceID);
    const sessionSeries = getSessionSeries(sessionId);
    const sessionReminders = getSessionRemindersForUser(sessionId);
    const sessionAnnouncements = getSessionAnnouncements(sessionId);
    
    return {
      ...session,
      teacher,
      host,
      space,
      series: sessionSeries,
      reminders: sessionReminders,
      announcements: sessionAnnouncements,
      isRegistered: user ? isUserRegisteredForSession(user.userID, sessionId) : false,
      canRegister: user && !isUserRegisteredForSession(user.userID, sessionId) && 
                   session.status === 'SCHEDULED' &&
                   new Date(session.dateTime) > new Date(),
      canUnregister: user && isUserRegisteredForSession(user.userID, sessionId) &&
                     (new Date(session.dateTime) - new Date()) > (2 * 60 * 60 * 1000), // 2 hours
      canBroadcast: user && canUserBroadcastToSession(user.userID, sessionId)
    };
  };

  const searchSessions = (query, filters = {}) => {
    let filteredSessions = sessions;

    // Text search
    if (query) {
      const searchTerm = query.toLowerCase();
      filteredSessions = filteredSessions.filter(session =>
        session.title.toLowerCase().includes(searchTerm) ||
        session.description.toLowerCase().includes(searchTerm) ||
        getUserById(session.teacherID)?.firstName.toLowerCase().includes(searchTerm) ||
        getUserById(session.teacherID)?.lastName.toLowerCase().includes(searchTerm)
      );
    }

    // Teacher filter
    if (filters.teacherId) {
      filteredSessions = filteredSessions.filter(session => 
        session.teacherID === filters.teacherId
      );
    }

    // Space filter
    if (filters.spaceId) {
      filteredSessions = filteredSessions.filter(session => 
        session.spaceID === filters.spaceId
      );
    }

    // Date range filter
    if (filters.startDate && filters.endDate) {
      const start = new Date(filters.startDate);
      const end = new Date(filters.endDate);
      filteredSessions = filteredSessions.filter(session => {
        const sessionDate = new Date(session.dateTime);
        return sessionDate >= start && sessionDate <= end;
      });
    }

    // Status filter
    if (filters.status) {
      filteredSessions = filteredSessions.filter(session => 
        session.status === filters.status
      );
    }

    return filteredSessions;
  };

  // Session broadcasting functionality
  const broadcastToSessionParticipants = async (sessionId, announcement) => {
    if (!user) {
      showError('Please log in to broadcast announcements');
      return { success: false, error: 'Not authenticated' };
    }

    try {
      setLoading(true);

      const session = getSessionById(sessionId);
      if (!session) {
        throw new Error('Session not found');
      }

      if (!canUserBroadcastToSession(user.userID, sessionId)) {
        throw new Error('Not authorized to broadcast to this session');
      }

      // Create broadcast message
      const broadcastMessage = {
        messageID: `message_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        messageType: 'ANNOUNCEMENT',
        title: announcement.title,
        content: announcement.content,
        fromUserID: user.userID,
        fromListeningSessionID: sessionId,
        fromReminderID: null,
        fromMessageReminderID: null,
        toUserID: null,
        spaceID: null,
        broadcastScope: 'SESSION_PARTICIPANTS',
        broadcastTargetID: sessionId,
        deliveryDate: new Date().toISOString(),
        isDelivered: true,
        isRead: false,
        priority: announcement.priority || 'NORMAL',
        reminderSettings: null,
        createdDate: new Date().toISOString(),
        generationSource: 'SESSION_ANNOUNCEMENT'
      };

      // In a real app, this would be sent to all session participants
      // For now, we'll just add to mock data
      showSuccess('Announcement sent to all session participants!');
      return { success: true, message: broadcastMessage };

    } catch (error) {
      showError(error.message);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const value = {
    sessions,
    loading,
    getAvailableSessions,
    getRegisteredSessions,
    getPastSessions,
    registerForSession,
    unregisterFromSession,
    createSession,
    updateSession,
    deleteSession,
    getSessionDetails,
    searchSessions,
    // Enhanced recurring session functions
    getRecurringSeries,
    getSessionSeries,
    // Enhanced reminder functions
    getSessionRemindersForUser,
    createSessionReminder,
    updateSessionReminder,
    deleteSessionReminder,
    // Broadcasting functions
    broadcastToSessionParticipants,
    loadSessions
  };

  return (
    <SessionContext.Provider value={value}>
      {children}
    </SessionContext.Provider>
  );
}; 