import React, { useState } from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  Button,
  Box,
  Chip,
  TextField,
  InputAdornment,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Avatar,
  IconButton,
  Tabs,
  Tab
} from '@mui/material';
import {
  Search,
  LibraryBooks,
  VideoLibrary,
  AudioFile,
  Article,
  BookmarkBorder,
  Bookmark,
  Share,
  OpenInNew,
  PlayArrow,
  AccessTime,
  Star
} from '@mui/icons-material';
import { mockResources } from '../../data/mockData';

const ResourcesPage = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [tabValue, setTabValue] = useState(0);
  const [bookmarkedResources, setBookmarkedResources] = useState(new Set(['resource-1']));

  // Filter resources
  const filteredResources = mockResources.filter(resource => {
    const matchesSearch = resource.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         resource.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         resource.tags.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()));
    const matchesCategory = !categoryFilter || resource.category === categoryFilter;
    return matchesSearch && matchesCategory;
  });

  // Group resources by type for tabs
  const videoResources = filteredResources.filter(r => r.resourceType === 'VIDEO');
  const documentResources = filteredResources.filter(r => r.resourceType === 'DOCUMENT');
  const linkResources = filteredResources.filter(r => r.resourceType === 'LINK');
  const dailyResources = filteredResources.filter(r => r.resourceType === 'DAILY_PHRASE');

  const getResourcesByTab = () => {
    switch (tabValue) {
      case 0: return filteredResources;
      case 1: return videoResources;
      case 2: return documentResources;
      case 3: return linkResources;
      case 4: return dailyResources;
      default: return filteredResources;
    }
  };

  const getCategories = () => {
    return [...new Set(mockResources.map(r => r.category))];
  };

  const toggleBookmark = (resourceId) => {
    const newBookmarks = new Set(bookmarkedResources);
    if (newBookmarks.has(resourceId)) {
      newBookmarks.delete(resourceId);
    } else {
      newBookmarks.add(resourceId);
    }
    setBookmarkedResources(newBookmarks);
  };

  const getResourceIcon = (type) => {
    switch (type) {
      case 'VIDEO': return <VideoLibrary />;
      case 'AUDIO': return <AudioFile />;
      case 'DOCUMENT': return <Article />;
      case 'LINK': return <OpenInNew />;
      case 'DAILY_PHRASE': return <Star />;
      default: return <LibraryBooks />;
    }
  };

  const ResourceCard = ({ resource }) => {
    const isBookmarked = bookmarkedResources.has(resource.resourceID);

    return (
      <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        {/* Thumbnail or Icon */}
        {resource.thumbnailURL ? (
          <CardMedia
            component="img"
            height="140"
            image={resource.thumbnailURL}
            alt={resource.title}
          />
        ) : (
          <Box sx={{ 
            height: 140, 
            bgcolor: 'grey.100', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center' 
          }}>
            <Avatar sx={{ width: 60, height: 60, bgcolor: 'primary.main' }}>
              {getResourceIcon(resource.resourceType)}
            </Avatar>
          </Box>
        )}

        <CardContent sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
          {/* Header */}
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 1 }}>
            <Typography variant="h6" sx={{ fontWeight: 600, fontSize: '1.1rem', flex: 1 }}>
              {resource.title}
            </Typography>
            <IconButton 
              size="small" 
              onClick={() => toggleBookmark(resource.resourceID)}
              sx={{ ml: 1 }}
            >
              {isBookmarked ? (
                <Bookmark sx={{ color: 'secondary.main' }} />
              ) : (
                <BookmarkBorder />
              )}
            </IconButton>
          </Box>

          {/* Type and Duration */}
          <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
            <Chip 
              label={resource.resourceType.replace('_', ' ')}
              size="small"
              color="primary"
              variant="outlined"
            />
            {resource.duration && (
              <Chip 
                label={`${resource.duration} min`}
                size="small"
                variant="outlined"
                icon={<AccessTime />}
              />
            )}
            <Chip 
              label={resource.difficulty}
              size="small"
              color={resource.difficulty === 'BEGINNER' ? 'success' : 'warning'}
            />
          </Box>

          {/* Description */}
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2, flex: 1 }}>
            {resource.description}
          </Typography>

          {/* Tags */}
          <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mb: 2 }}>
            {resource.tags.slice(0, 3).map((tag) => (
              <Chip 
                key={tag}
                label={tag}
                size="small"
                variant="outlined"
                sx={{ fontSize: '0.7rem' }}
              />
            ))}
            {resource.tags.length > 3 && (
              <Chip 
                label={`+${resource.tags.length - 3} more`}
                size="small"
                variant="outlined"
                sx={{ fontSize: '0.7rem' }}
              />
            )}
          </Box>

          {/* Actions */}
          <Box sx={{ display: 'flex', gap: 1, mt: 'auto' }}>
            <Button
              variant="contained"
              size="small"
              startIcon={resource.resourceType === 'VIDEO' ? <PlayArrow /> : <OpenInNew />}
              onClick={() => {
                if (resource.contentURL) {
                  window.open(resource.contentURL, '_blank');
                }
              }}
              sx={{ flex: 1 }}
            >
              {resource.resourceType === 'VIDEO' ? 'Watch' : 'Access'}
            </Button>
            <IconButton size="small" sx={{ border: '1px solid', borderColor: 'divider' }}>
              <Share />
            </IconButton>
          </Box>
        </CardContent>
      </Card>
    );
  };

  return (
    <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
      {/* Header */}
      <Box sx={{ mb: 3 }}>
        <Typography variant="h4" sx={{ fontWeight: 600, mb: 1 }}>
          Learning Resources
        </Typography>
        <Typography variant="body1" color="text.secondary">
          Explore Buddhist teachings, chanting videos, articles, and daily wisdom
        </Typography>
      </Box>

      {/* Search and Filters */}
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                placeholder="Search resources, topics, or keywords..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Search />
                    </InputAdornment>
                  ),
                }}
              />
            </Grid>

            <Grid item xs={12} md={4}>
              <FormControl fullWidth>
                <InputLabel>Category</InputLabel>
                <Select
                  value={categoryFilter}
                  label="Category"
                  onChange={(e) => setCategoryFilter(e.target.value)}
                >
                  <MenuItem value="">All Categories</MenuItem>
                  {getCategories().map((category) => (
                    <MenuItem key={category} value={category}>
                      {category}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid item xs={12} md={2}>
              <Button
                fullWidth
                variant="outlined"
                onClick={() => {
                  setSearchQuery('');
                  setCategoryFilter('');
                }}
              >
                Clear
              </Button>
            </Grid>
          </Grid>
        </CardContent>
      </Card>

      {/* Tabs */}
      <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}>
        <Tabs value={tabValue} onChange={(e, newValue) => setTabValue(newValue)} variant="scrollable">
          <Tab label={`All (${filteredResources.length})`} icon={<LibraryBooks />} />
          <Tab label={`Videos (${videoResources.length})`} icon={<VideoLibrary />} />
          <Tab label={`Documents (${documentResources.length})`} icon={<Article />} />
          <Tab label={`Links (${linkResources.length})`} icon={<OpenInNew />} />
          <Tab label={`Daily Wisdom (${dailyResources.length})`} icon={<Star />} />
        </Tabs>
      </Box>

      {/* Resources Grid */}
      <Grid container spacing={3}>
        {getResourcesByTab().length === 0 ? (
          <Grid item xs={12}>
            <Card>
              <CardContent sx={{ textAlign: 'center', py: 6 }}>
                <LibraryBooks sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
                <Typography variant="h6" color="text.secondary" sx={{ mb: 1 }}>
                  No resources found
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Try adjusting your search criteria or browse different categories.
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ) : (
          getResourcesByTab().map((resource) => (
            <Grid item xs={12} sm={6} md={4} key={resource.resourceID}>
              <ResourceCard resource={resource} />
            </Grid>
          ))
        )}
      </Grid>

      {/* Daily Phrase Featured Section */}
      {dailyResources.length > 0 && tabValue === 0 && (
        <Box sx={{ mt: 4 }}>
          <Typography variant="h5" sx={{ fontWeight: 600, mb: 2 }}>
            Today's Featured Wisdom
          </Typography>
          <Card sx={{ background: 'linear-gradient(135deg, #ff9800 0%, #ffb74d 100%)', color: 'white' }}>
            <CardContent sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                <Star sx={{ mr: 1 }} />
                <Typography variant="h6" sx={{ fontWeight: 600 }}>
                  {dailyResources[0].title}
                </Typography>
              </Box>
              <Typography variant="body1" sx={{ fontStyle: 'italic', lineHeight: 1.6, mb: 2 }}>
                {dailyResources[0].description}
              </Typography>
              <Box sx={{ display: 'flex', gap: 1 }}>
                <Button variant="outlined" sx={{ color: 'white', borderColor: 'white' }}>
                  Share Quote
                </Button>
                <Button 
                  variant="outlined" 
                  sx={{ color: 'white', borderColor: 'white' }}
                  onClick={() => toggleBookmark(dailyResources[0].resourceID)}
                >
                  {bookmarkedResources.has(dailyResources[0].resourceID) ? 'Saved' : 'Save'}
                </Button>
              </Box>
            </CardContent>
          </Card>
        </Box>
      )}
    </Container>
  );
};

export default ResourcesPage; 