import React, { useState, useEffect } from 'react';
import {
  Box,
  Grid,
  Card,
  CardContent,
  Typography,
  List,
  ListItem,
  ListItemText,
  Avatar,
  Button,
  Alert,
  LinearProgress
} from '@mui/material';
import {
  People as PeopleIcon,
  Event as EventIcon,
  School as SchoolIcon,
  Notifications as NotificationsIcon,
  Warning as WarningIcon,
  CheckCircle as CheckCircleIcon,
  Schedule as ScheduleIcon,
  Language as LanguageIcon,
  Public as PublicIcon
} from '@mui/icons-material';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../../contexts/AuthContext';
import { 
  mockUsers, 
  mockSessions, 
  mockSpaces, 
  mockMessages, 
  getUserById, 
  getSpaceById,
  getUserNotifications
} from '../../data/mockData';

export default function AdminDashboard() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);

  // Calculate stats from real mock data
  const calculateStats = () => {
    const totalUsers = mockUsers.length;
    const activeUsers = mockUsers.filter(u => u.isActive).length;
    const totalSessions = mockSessions.length;
    const upcomingSessions = mockSessions.filter(s => 
      s.status === 'SCHEDULED' || s.status === 'IN_PROGRESS'
    ).length;
    const totalSpaces = mockSpaces.length;
    const activeSpaces = mockSpaces.filter(s => s.isActive).length;
    const totalNotifications = mockMessages.length;
    const unreadNotifications = mockMessages.filter(m => !m.isRead).length;

    return {
      totalUsers,
      activeUsers,
      totalSessions,
      upcomingSessions,
      totalSpaces,
      activeSpaces,
      totalNotifications,
      unreadNotifications
    };
  };

  const stats = calculateStats();

  // Generate recent activities from actual data
  const generateRecentActivities = () => {
    const activities = [];
    
    // Add user activities
    const recentUsers = mockUsers
      .filter(u => u.createdDate)
      .sort((a, b) => new Date(b.createdDate) - new Date(a.createdDate))
      .slice(0, 2);
    
    recentUsers.forEach(user => {
      activities.push({
        id: `user_${user.userID}`,
        type: 'user_joined',
        message: `${user.firstName} ${user.lastName} joined the platform`,
        timestamp: user.createdDate,
        icon: PeopleIcon,
        color: 'success'
      });
    });

    // Add session activities
    const recentSessions = mockSessions
      .filter(s => s.createdDate)
      .sort((a, b) => new Date(b.createdDate) - new Date(a.createdDate))
      .slice(0, 2);
    
    recentSessions.forEach(session => {
      activities.push({
        id: `session_${session.sessionID}`,
        type: 'session_created',
        message: `New session "${session.title}" scheduled`,
        timestamp: session.createdDate,
        icon: EventIcon,
        color: 'primary'
      });
    });

    // Add space activities
    const recentSpaces = mockSpaces
      .filter(s => s.createdDate)
      .sort((a, b) => new Date(b.createdDate) - new Date(a.createdDate))
      .slice(0, 1);
    
    recentSpaces.forEach(space => {
      activities.push({
        id: `space_${space.spaceID}`,
        type: 'space_created',
        message: `Learning space "${space.spaceName}" created`,
        timestamp: space.createdDate,
        icon: SchoolIcon,
        color: 'info'
      });
    });

    return activities
      .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp))
      .slice(0, 4);
  };

  const activities = generateRecentActivities();

  // Generate upcoming sessions
  const generateUpcomingSessions = () => {
    const now = new Date();
    return mockSessions
      .filter(s => new Date(s.dateTime) > now && (s.status === 'SCHEDULED' || s.status === 'IN_PROGRESS'))
      .sort((a, b) => new Date(a.dateTime) - new Date(b.dateTime))
      .slice(0, 3)
      .map(session => ({
        id: session.sessionID,
        title: session.title,
        teacher: getUserById(session.teacherID)?.firstName + ' ' + getUserById(session.teacherID)?.lastName,
        time: session.dateTime,
        participants: session.registrations?.length || 0,
        space: getSpaceById(session.spaceID)?.spaceName
      }));
  };

  const upcomingSessions = generateUpcomingSessions();

  useEffect(() => {
    // Simulate loading dashboard data
    const loadDashboard = async () => {
      await new Promise(resolve => setTimeout(resolve, 1000));
      setLoading(false);
    };
    loadDashboard();
  }, []);

  const StatCard = ({ title, value, subtitle, icon: Icon, color = 'primary', progress }) => (
    <Card>
      <CardContent>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
          <Avatar sx={{ bgcolor: `${color}.main`, mr: 2 }}>
            <Icon />
          </Avatar>
          <Box sx={{ flexGrow: 1 }}>
            <Typography variant="h4" component="div">
              {loading ? '...' : value}
            </Typography>
            <Typography variant="h6" color="text.secondary">
              {title}
            </Typography>
          </Box>
        </Box>
        {subtitle && (
          <Typography variant="body2" color="text.secondary">
            {subtitle}
          </Typography>
        )}
        {progress !== undefined && (
          <Box sx={{ mt: 2 }}>
            <LinearProgress variant="determinate" value={progress} color={color} />
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              {progress}% {t('active')}
            </Typography>
          </Box>
        )}
      </CardContent>
    </Card>
  );

  if (loading) {
    return (
      <Box sx={{ p: 3 }}>
        <Typography variant="h4" gutterBottom>
          {t('Dashboard')}
        </Typography>
        <LinearProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h4" gutterBottom>
        {t('Admin Dashboard')}
      </Typography>
      
      <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
        {t('Welcome back')}, {user?.firstName}! {t('Here\'s what\'s happening in your Buddhist learning community.')}
      </Typography>

      {/* Quick Stats */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title={t('Total Users')}
            value={stats.totalUsers}
            subtitle={`${stats.activeUsers} ${t('active users')}`}
            icon={PeopleIcon}
            color="primary"
            progress={Math.round((stats.activeUsers / stats.totalUsers) * 100)}
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title={t('Sessions')}
            value={stats.totalSessions}
            subtitle={`${stats.upcomingSessions} ${t('upcoming')}`}
            icon={EventIcon}
            color="success"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title={t('Learning Spaces')}
            value={stats.totalSpaces}
            subtitle={`${stats.activeSpaces} ${t('active spaces')}`}
            icon={SchoolIcon}
            color="info"
            progress={Math.round((stats.activeSpaces / stats.totalSpaces) * 100)}
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title={t('Notifications')}
            value={stats.totalNotifications}
            subtitle={`${stats.unreadNotifications} ${t('unread')}`}
            icon={NotificationsIcon}
            color="warning"
          />
        </Grid>
      </Grid>

      <Grid container spacing={3}>
        {/* Recent Activities */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                {t('Recent Activities')}
              </Typography>
              <List>
                {activities.map((activity, index) => {
                  const IconComponent = activity.icon;
                  return (
                    <ListItem key={activity.id} sx={{ px: 0 }}>
                      <Avatar sx={{ bgcolor: `${activity.color}.main`, mr: 2, width: 32, height: 32 }}>
                        <IconComponent sx={{ fontSize: 16 }} />
                      </Avatar>
                      <ListItemText
                        primary={activity.message}
                        secondary={new Date(activity.timestamp).toLocaleString()}
                      />
                    </ListItem>
                  );
                })}
              </List>
              <Button fullWidth sx={{ mt: 1 }}>
                {t('View All Activities')}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        {/* Upcoming Sessions */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                {t('Upcoming Sessions')}
              </Typography>
              <List>
                {upcomingSessions.map((session, index) => (
                  <ListItem key={session.id} sx={{ px: 0 }}>
                    <Avatar sx={{ bgcolor: 'primary.main', mr: 2, width: 32, height: 32 }}>
                      <ScheduleIcon sx={{ fontSize: 16 }} />
                    </Avatar>
                    <ListItemText
                      primary={session.title}
                      secondary={
                        <Box>
                          <Typography variant="body2" component="span">
                            {session.teacher} • {session.participants} {t('participants')}
                          </Typography>
                          <br />
                          <Typography variant="body2" color="text.secondary" component="span">
                            {new Date(session.time).toLocaleString()} • {session.space}
                          </Typography>
                        </Box>
                      }
                    />
                  </ListItem>
                ))}
              </List>
              <Button fullWidth sx={{ mt: 1 }}>
                {t('Manage Sessions')}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        {/* System Status */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                {t('System Status')}
              </Typography>
              <Grid container spacing={2}>
                <Grid item xs={12} sm={6} md={3}>
                  <Alert 
                    severity="success" 
                    icon={<CheckCircleIcon />}
                    sx={{ mb: 1 }}
                  >
                    {t('All systems operational')}
                  </Alert>
                </Grid>
                <Grid item xs={12} sm={6} md={3}>
                  <Alert 
                    severity="info" 
                    icon={<LanguageIcon />}
                    sx={{ mb: 1 }}
                  >
                    {t('5 languages supported')}
                  </Alert>
                </Grid>
                <Grid item xs={12} sm={6} md={3}>
                  <Alert 
                    severity="info" 
                    icon={<PublicIcon />}
                    sx={{ mb: 1 }}
                  >
                    {t('Global timezone support')}
                  </Alert>
                </Grid>
                <Grid item xs={12} sm={6} md={3}>
                  <Alert 
                    severity="warning" 
                    icon={<WarningIcon />}
                    sx={{ mb: 1 }}
                  >
                    {t('2 pending updates')}
                  </Alert>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
} 