import React, { useState } from 'react';
import {
  Box,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  Button,
  IconButton,
  Avatar
} from '@mui/material';
import {
  Edit as EditIcon,
  Delete as DeleteIcon,
  People as PeopleIcon,
  Event as EventIcon,
  Add as AddIcon
} from '@mui/icons-material';
import { useTranslation } from 'react-i18next';
import { mockSpaces, mockSessions, getUserById } from '../../data/mockData';

export default function AdminSpaceManagement() {
  const { t } = useTranslation();
  const [spaces] = useState(mockSpaces);

  // Helper function to get space statistics
  const getSpaceStats = (spaceId) => {
    const spaceSessions = mockSessions.filter(session => session.spaceID === spaceId);
    const memberCount = spaces.find(s => s.spaceID === spaceId)?.members?.length || 0;
    return {
      memberCount,
      sessionCount: spaceSessions.length
    };
  };

  // Helper function to get creator name
  const getCreatorName = (userId) => {
    const user = getUserById(userId);
    return user ? `${user.firstName} ${user.lastName}` : 'Unknown';
  };

  return (
    <Box sx={{ p: 3 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h4">
          {t('Space Management')}
        </Typography>
        <Button variant="contained" startIcon={<AddIcon />}>
          {t('Create Space')}
        </Button>
      </Box>

      <TableContainer component={Paper}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>{t('Space')}</TableCell>
              <TableCell>{t('Description')}</TableCell>
              <TableCell>{t('Language')}</TableCell>
              <TableCell>{t('Members')}</TableCell>
              <TableCell>{t('Sessions')}</TableCell>
              <TableCell>{t('Status')}</TableCell>
              <TableCell>{t('Created By')}</TableCell>
              <TableCell>{t('Created')}</TableCell>
              <TableCell align="right">{t('Actions')}</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {spaces.map((space) => {
              const stats = getSpaceStats(space.spaceID);
              return (
                <TableRow key={space.spaceID}>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <Avatar sx={{ mr: 2, bgcolor: 'primary.main' }}>
                        {space.spaceName[0]}
                      </Avatar>
                      <Typography variant="subtitle2">
                        {space.spaceName}
                      </Typography>
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" sx={{ maxWidth: 300 }}>
                      {space.spaceDescription}
                    </Typography>
                  </TableCell>
                  <TableCell>
                    <Chip 
                      size="small" 
                      label={space.language.toUpperCase()} 
                      color="default"
                      variant="outlined"
                    />
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <PeopleIcon sx={{ fontSize: 16, mr: 0.5 }} />
                      {stats.memberCount}
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <EventIcon sx={{ fontSize: 16, mr: 0.5 }} />
                      {stats.sessionCount}
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Chip 
                      size="small" 
                      color={space.isActive ? 'success' : 'error'} 
                      label={t(space.isActive ? 'Active' : 'Inactive')} 
                    />
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2">
                      {getCreatorName(space.createdBy)}
                    </Typography>
                  </TableCell>
                  <TableCell>{new Date(space.createdDate).toLocaleDateString()}</TableCell>
                  <TableCell align="right">
                    <IconButton size="small">
                      <EditIcon />
                    </IconButton>
                    <IconButton size="small">
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
} 