import React, { useState, useEffect } from 'react';
import { 
  Box, 
  Paper, 
  TextField, 
  Button, 
  Typography, 
  Alert,
  CircularProgress,
  Grid,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  IconButton,
  InputAdornment,
  Stepper,
  Step,
  StepLabel
} from '@mui/material';
import { 
  VisibilityOutlined, 
  VisibilityOffOutlined,
  ArrowBackOutlined,
  LanguageOutlined 
} from '@mui/icons-material';
import { styled } from '@mui/material/styles';
import { useTranslation } from 'react-i18next';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';

const RegisterContainer = styled(Box)(({ theme }) => ({
  minHeight: '100vh',
  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  padding: theme.spacing(2),
}));

const RegisterPaper = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(4),
  maxWidth: 500,
  width: '100%',
  borderRadius: 16,
  boxShadow: '0 8px 32px rgba(0,0,0,0.1)',
}));

const LogoContainer = styled(Box)({
  textAlign: 'center',
  marginBottom: '24px',
});

const Lotus = styled('div')(({ theme }) => ({
  width: '50px',
  height: '50px',
  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
  borderRadius: '50% 50% 50% 50% / 60% 60% 40% 40%',
  position: 'relative',
  margin: '0 auto 12px',
  
  '&::before': {
    content: '""',
    position: 'absolute',
    top: '6px',
    left: '6px',
    width: '38px',
    height: '38px',
    background: 'rgba(255, 255, 255, 0.3)',
    borderRadius: '50% 50% 50% 50% / 60% 60% 40% 40%',
  },
}));

// Common timezones for easy selection
const commonTimezones = [
  'America/New_York',
  'America/Los_Angeles',
  'America/Chicago',
  'Europe/London',
  'Europe/Paris',
  'Europe/Berlin',
  'Europe/Madrid',
  'Asia/Tokyo',
  'Asia/Shanghai',
  'Asia/Kolkata',
  'Asia/Seoul',
  'Asia/Ho_Chi_Minh',
  'Australia/Sydney',
  'Pacific/Auckland'
];

const steps = ['Personal Info', 'Preferences', 'Complete'];

function RegisterScreen() {
  const { t, i18n } = useTranslation();
  const { register } = useAuth();
  const navigate = useNavigate();
  const [activeStep, setActiveStep] = useState(0);
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    confirmPassword: '',
    country: '',
    place: '',
    timezone: '',
    language: i18n.language
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  useEffect(() => {
    // Auto-detect timezone
    if (!formData.timezone) {
      const detectedTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
      setFormData(prev => ({
        ...prev,
        timezone: detectedTimezone
      }));
    }
  }, [formData.timezone]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    if (error) setError('');
  };

  const handleNext = () => {
    if (validateCurrentStep()) {
      setActiveStep(prev => prev + 1);
    }
  };

  const handleBack = () => {
    setActiveStep(prev => prev - 1);
  };

  const validateCurrentStep = () => {
    setError('');
    
    if (activeStep === 0) {
      if (!formData.firstName || !formData.lastName || !formData.email) {
        setError('Please fill in all required fields');
        return false;
      }
      if (!formData.email.includes('@')) {
        setError('Please enter a valid email address');
        return false;
      }
    }
    
    if (activeStep === 1) {
      if (!formData.password || !formData.confirmPassword) {
        setError('Please enter and confirm your password');
        return false;
      }
      if (formData.password.length < 6) {
        setError('Password must be at least 6 characters long');
        return false;
      }
      if (formData.password !== formData.confirmPassword) {
        setError('Passwords do not match');
        return false;
      }
    }
    
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateCurrentStep()) return;
    
    setLoading(true);
    setError('');

    try {
      const result = await register(formData);
      if (!result.success) {
        setError(result.error);
      } else {
        // Registration successful, user will be automatically logged in
        navigate('/');
      }
    } catch (err) {
      setError('An unexpected error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleLanguageChange = (event) => {
    const newLanguage = event.target.value;
    i18n.changeLanguage(newLanguage);
    localStorage.setItem('language', newLanguage);
    setFormData(prev => ({
      ...prev,
      language: newLanguage
    }));
  };

  const renderStepContent = () => {
    switch (activeStep) {
      case 0:
        return (
          <Grid container spacing={2}>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label={t('firstName')}
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                required
                disabled={loading}
                autoComplete="given-name"
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label={t('lastName')}
                name="lastName"
                value={formData.lastName}
                onChange={handleChange}
                required
                disabled={loading}
                autoComplete="family-name"
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label={t('email')}
                name="email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                required
                disabled={loading}
                autoComplete="email"
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label={t('country')}
                name="country"
                value={formData.country}
                onChange={handleChange}
                disabled={loading}
                autoComplete="country"
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label="City/Province"
                name="place"
                value={formData.place}
                onChange={handleChange}
                disabled={loading}
                autoComplete="address-level1"
              />
            </Grid>
          </Grid>
        );

      case 1:
        return (
          <Grid container spacing={2}>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label={t('password')}
                name="password"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                required
                disabled={loading}
                autoComplete="new-password"
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowPassword(!showPassword)}
                        edge="end"
                      >
                        {showPassword ? <VisibilityOffOutlined /> : <VisibilityOutlined />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label={t('confirmPassword')}
                name="confirmPassword"
                type={showConfirmPassword ? 'text' : 'password'}
                value={formData.confirmPassword}
                onChange={handleChange}
                required
                disabled={loading}
                autoComplete="new-password"
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                        edge="end"
                      >
                        {showConfirmPassword ? <VisibilityOffOutlined /> : <VisibilityOutlined />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <FormControl fullWidth>
                <InputLabel>{t('timezone')}</InputLabel>
                <Select
                  name="timezone"
                  value={formData.timezone}
                  onChange={handleChange}
                  label={t('timezone')}
                  disabled={loading}
                >
                  {commonTimezones.map(tz => (
                    <MenuItem key={tz} value={tz}>
                      {tz.replace('_', ' ')}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} sm={6}>
              <FormControl fullWidth>
                <InputLabel>{t('language')}</InputLabel>
                <Select
                  name="language"
                  value={formData.language}
                  onChange={handleLanguageChange}
                  label={t('language')}
                  disabled={loading}
                >
                  <MenuItem value="en">English</MenuItem>
                  <MenuItem value="ja">日本語</MenuItem>
                  <MenuItem value="fr">Français</MenuItem>
                  <MenuItem value="es">Español</MenuItem>
                  <MenuItem value="vi">Tiếng Việt</MenuItem>
                </Select>
              </FormControl>
            </Grid>
          </Grid>
        );

      case 2:
        return (
          <Box sx={{ textAlign: 'center', py: 2 }}>
            <Typography variant="h6" gutterBottom>
              Welcome to Gakuto!
            </Typography>
            <Typography variant="body2" color="textSecondary" sx={{ mb: 3 }}>
              Your account is ready. You'll be joining a global community of Buddhist learners.
            </Typography>
            <Alert severity="info" sx={{ mb: 3 }}>
              After registration, you'll be able to:
              <ul style={{ textAlign: 'left', marginTop: 8, paddingLeft: 20 }}>
                <li>Join learning sessions and meditation groups</li>
                <li>Access Buddhism resources and teachings</li>
                <li>Connect with teachers and fellow practitioners</li>
                <li>Receive personalized session reminders</li>
              </ul>
            </Alert>
          </Box>
        );

      default:
        return null;
    }
  };

  return (
    <RegisterContainer>
      <RegisterPaper elevation={3}>
        {/* Back to Login */}
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
          <IconButton component={Link} to="/login" sx={{ mr: 1 }}>
            <ArrowBackOutlined />
          </IconButton>
          <FormControl size="small" sx={{ minWidth: 100 }}>
            <Select
              value={i18n.language}
              onChange={handleLanguageChange}
              startAdornment={<LanguageOutlined sx={{ mr: 1, color: 'text.secondary' }} />}
              displayEmpty
              variant="outlined"
            >
              <MenuItem value="en">EN</MenuItem>
              <MenuItem value="ja">日本語</MenuItem>
              <MenuItem value="fr">FR</MenuItem>
              <MenuItem value="es">ES</MenuItem>
              <MenuItem value="vi">VI</MenuItem>
            </Select>
          </FormControl>
        </Box>

        {/* Logo and Title */}
        <LogoContainer>
          <Lotus />
          <Typography 
            variant="h5" 
            sx={{ 
              fontFamily: '"Noto Serif", serif',
              fontWeight: 600,
              color: 'primary.main',
              mb: 1
            }}
          >
            Join Gakuto
          </Typography>
          <Typography variant="body2" color="textSecondary">
            Create your Buddhist learning account
          </Typography>
        </LogoContainer>

        {/* Progress Stepper */}
        <Stepper activeStep={activeStep} sx={{ mb: 3 }}>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>

        {/* Error Alert */}
        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
          </Alert>
        )}

        {/* Form Content */}
        <Box component="form" onSubmit={handleSubmit}>
          {renderStepContent()}

          {/* Navigation Buttons */}
          <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
            <Button
              disabled={activeStep === 0 || loading}
              onClick={handleBack}
              variant="outlined"
            >
              Back
            </Button>
            
            {activeStep === steps.length - 1 ? (
              <Button
                type="submit"
                variant="contained"
                disabled={loading}
                sx={{ minWidth: 120 }}
              >
                {loading ? <CircularProgress size={24} /> : t('register')}
              </Button>
            ) : (
              <Button
                variant="contained"
                onClick={handleNext}
                disabled={loading}
              >
                Next
              </Button>
            )}
          </Box>
        </Box>

        {/* Login Link */}
        <Typography variant="body2" color="textSecondary" align="center" sx={{ mt: 3 }}>
          Already have an account?{' '}
          <Link 
            to="/login" 
            style={{ 
              color: 'inherit', 
              textDecoration: 'none',
              fontWeight: 500
            }}
          >
            {t('login')}
          </Link>
        </Typography>
      </RegisterPaper>
    </RegisterContainer>
  );
}

export default RegisterScreen; 