import React, { useState, useEffect } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { Box } from '@mui/material';
import { useTranslation } from 'react-i18next';

// Context Providers
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { NotificationProvider } from './contexts/NotificationContext';
import { SessionProvider } from './contexts/SessionContext';

// Layout Components
import MobileLayout from './components/Layout/MobileLayout';
import AdminLayout from './components/Layout/AdminLayout';

// Authentication Components
import LoginScreen from './components/Auth/LoginScreen';
import RegisterScreen from './components/Auth/RegisterScreen';

// Mobile Pages
import HomePage from './components/Pages/HomePage';
import SessionsPage from './components/Pages/SessionsPage';
import SessionDetailsPage from './components/Pages/SessionDetailsPage';
import ResourcesPage from './components/Pages/ResourcesPage';
import ProfilePage from './components/Pages/ProfilePage';
import NotificationsPage from './components/Pages/NotificationsPage';
import SpacesPage from './components/Pages/SpacesPage';

// Admin Pages
import AdminDashboard from './components/Admin/AdminDashboard';
import AdminSessionManagement from './components/Admin/AdminSessionManagement';
import AdminUserManagement from './components/Admin/AdminUserManagement';
import AdminSpaceManagement from './components/Admin/AdminSpaceManagement';

// Utility Components
import ProtectedRoute from './components/Common/ProtectedRoute';
import LoadingScreen from './components/Common/LoadingScreen';
import ErrorBoundary from './components/Common/ErrorBoundary';

// Service Worker Registration
import './utils/serviceWorkerRegistration';

// Add cache-busting for development
const isDevelopment = process.env.NODE_ENV === 'development';

function AppRoutes() {
  const { user, loading } = useAuth();
  const { i18n } = useTranslation();
  const [appLoading, setAppLoading] = useState(true);

  useEffect(() => {
    // Simulate app initialization
    const initializeApp = async () => {
      try {
        // Load user preferences
        const savedLanguage = localStorage.getItem('language');
        if (savedLanguage) {
          i18n.changeLanguage(savedLanguage);
        }
        
        // Add cache-busting headers for development
        if (isDevelopment) {
          // Force reload service worker in development
          if ('serviceWorker' in navigator) {
            navigator.serviceWorker.getRegistrations().then((registrations) => {
              registrations.forEach((registration) => {
                registration.unregister();
              });
            });
          }
        }
        
        // Initialize other app services
        await new Promise(resolve => setTimeout(resolve, 1500));
        
      } catch (error) {
        console.error('App initialization error:', error);
      } finally {
        setAppLoading(false);
      }
    };

    initializeApp();
  }, [i18n]);

  if (appLoading || loading) {
    return <LoadingScreen />;
  }

  if (!user) {
    return (
      <Box sx={{ minHeight: '100vh', bgcolor: 'background.default' }}>
        <Routes>
          <Route path="/login" element={<LoginScreen />} />
          <Route path="/register" element={<RegisterScreen />} />
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Box>
    );
  }

  // Admin routes for teachers, moderators, and administrators
        if (user.roles.some(role => ['TEACHER', 'SYS_ADMIN'].includes(role))) {
    return (
      <Routes>
        {/* Mobile App Routes */}
        <Route path="/" element={<MobileLayout />}>
          <Route index element={<HomePage />} />
          <Route path="sessions" element={<SessionsPage />} />
          <Route path="sessions/:sessionId" element={<SessionDetailsPage />} />
          <Route path="resources" element={<ResourcesPage />} />
          <Route path="profile" element={<ProfilePage />} />
          <Route path="notifications" element={<NotificationsPage />} />
          <Route path="spaces" element={<SpacesPage />} />
        </Route>

        {/* Admin Web Interface Routes */}
        <Route path="/admin" element={<AdminLayout />}>
          <Route index element={<AdminDashboard />} />
          <Route path="sessions" element={<AdminSessionManagement />} />
          <Route path="users" element={
            <ProtectedRoute requiredRoles={['SYS_ADMIN', 'TEACHER']}>
              <AdminUserManagement />
            </ProtectedRoute>
          } />
          <Route path="spaces" element={<AdminSpaceManagement />} />
        </Route>

        {/* Fallback */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    );
  }

  // Regular student routes
  return (
    <Routes>
      <Route path="/" element={<MobileLayout />}>
        <Route index element={<HomePage />} />
        <Route path="sessions" element={<SessionsPage />} />
        <Route path="sessions/:sessionId" element={<SessionDetailsPage />} />
        <Route path="resources" element={<ResourcesPage />} />
        <Route path="profile" element={<ProfilePage />} />
        <Route path="notifications" element={<NotificationsPage />} />
        <Route path="spaces" element={<SpacesPage />} />
      </Route>
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <AuthProvider>
        <NotificationProvider>
          <SessionProvider>
            <AppRoutes />
          </SessionProvider>
        </NotificationProvider>
      </AuthProvider>
    </ErrorBoundary>
  );
}

export default App; 