import React, { useState } from 'react';
import {
  Box,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Grid,
  Fab,
  Menu,
  ListItemIcon,
  ListItemText,
  Link
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  MoreVert as MoreVertIcon,
  People as PeopleIcon,
  VideoCall as VideoCallIcon,
  Repeat as RepeatIcon,
  OpenInNew as OpenInNewIcon
} from '@mui/icons-material';
import { useTranslation } from 'react-i18next';
import { 
  mockSessions, 
  mockSpaces, 
  mockUsers, 
  getUserById, 
  getSpaceById
} from '../../data/mockData';

export default function AdminSessionManagement() {
  const { t } = useTranslation();
  const [sessions, setSessions] = useState(mockSessions);
  const [selectedSession, setSelectedSession] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [anchorEl, setAnchorEl] = useState(null);
  const [menuSessionId, setMenuSessionId] = useState(null);

  // Get teachers and spaces from mock data
  const mockTeachers = mockUsers.filter(user => user.roles.includes('TEACHER'));
  const mockSpacesData = mockSpaces;

  const [formData, setFormData] = useState({
    title: '',
    teacherId: '',
    spaceId: '',
    startTime: '',
    duration: 60,
    maxParticipants: 30,
    recurring: 'none',
    meetingUrl: ''
  });

  // Helper functions to get names for display
  const getTeacherName = (teacherId) => {
    const teacher = getUserById(teacherId);
    return teacher ? `${teacher.firstName} ${teacher.lastName}` : 'Unknown';
  };

  const getSpaceName = (spaceId) => {
    const space = getSpaceById(spaceId);
    return space ? space.spaceName : 'Unknown';
  };

  const getHostName = (hostId) => {
    const host = getUserById(hostId);
    return host ? `${host.firstName} ${host.lastName}` : 'Unknown';
  };

  const getRecurringType = (session) => {
    if (session.sessionType === 'SINGLE') return 'none';
    if (session.recurrencePattern?.frequency === 'WEEKLY') return 'weekly';
    if (session.recurrencePattern?.frequency === 'DAILY') return 'daily';
    return 'weekly';
  };

  const getParticipantCount = (session) => {
    return session.registrations?.length || 0;
  };

  const handleCreateSession = () => {
    setSelectedSession(null);
    setIsEditing(false);
    setFormData({
      title: '',
      teacherId: '',
      spaceId: '',
      startTime: '',
      duration: 60,
      maxParticipants: 30,
      recurring: 'none',
      meetingUrl: ''
    });
    setOpenDialog(true);
  };

  const handleEditSession = (session) => {
    setSelectedSession(session);
    setIsEditing(true);
    setFormData({
      title: session.title,
      teacherId: session.teacherID,
      spaceId: session.spaceID,
      startTime: new Date(session.dateTime).toISOString().slice(0, 16),
      duration: session.duration,
      maxParticipants: 50, // Default value since not in mock data
      recurring: getRecurringType(session),
      meetingUrl: session.meetingRoomURL
    });
    setOpenDialog(true);
    setAnchorEl(null);
  };

  const handleDeleteSession = (sessionId) => {
    setSessions(sessions.filter(s => s.sessionID !== sessionId));
    setAnchorEl(null);
  };

  const handleSaveSession = () => {
    if (isEditing) {
      setSessions(sessions.map(s => 
        s.sessionID === selectedSession.sessionID 
          ? { ...s, ...formData, dateTime: new Date(formData.startTime).toISOString() }
          : s
      ));
    } else {
      const newSession = {
        sessionID: `session_${Date.now()}`,
        ...formData,
        dateTime: new Date(formData.startTime).toISOString(),
        status: 'SCHEDULED',
        registrations: [],
        sessionType: formData.recurring === 'none' ? 'SINGLE' : 'RECURRING_MASTER',
        recurrencePattern: formData.recurring !== 'none' ? {
          frequency: formData.recurring.toUpperCase(),
          interval: 1
        } : null,
        timezone: 'Asia/Tokyo',
        meetingRoomURL: formData.meetingUrl,
        teacherID: formData.teacherId,
        spaceID: formData.spaceId,
        createdDate: new Date().toISOString(),
        lastModifiedDate: new Date().toISOString()
      };
      setSessions([...sessions, newSession]);
    }
    setOpenDialog(false);
  };

  const handleMenuOpen = (event, sessionId) => {
    setAnchorEl(event.currentTarget);
    setMenuSessionId(sessionId);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
    setMenuSessionId(null);
  };

  const getStatusChip = (status) => {
    const statusConfig = {
      SCHEDULED: { color: 'primary', label: t('Scheduled') },
      IN_PROGRESS: { color: 'success', label: t('In Progress') },
      COMPLETED: { color: 'default', label: t('Completed') },
      CANCELLED: { color: 'error', label: t('Cancelled') }
    };
    const config = statusConfig[status] || statusConfig.SCHEDULED;
    return <Chip size="small" color={config.color} label={config.label} />;
  };

  const getRecurringChip = (recurring) => {
    if (recurring === 'none') return (
      <Chip size="small" variant="outlined" label={t('One-time')} />
    );
    const labels = {
      daily: t('Daily'),
      weekly: t('Weekly'),
      monthly: t('Monthly')
    };
    return <Chip size="small" variant="outlined" icon={<RepeatIcon />} label={labels[recurring] || t('Recurring')} />;
  };

  return (
    <Box sx={{ p: 3 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h4">
          {t('Session Management')}
        </Typography>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleCreateSession}
        >
          {t('Create Session')}
        </Button>
      </Box>

      <TableContainer component={Paper}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>{t('Session')}</TableCell>
              <TableCell>{t('Teacher')}</TableCell>
              <TableCell>{t('Space')}</TableCell>
              <TableCell>{t('Date & Time')}</TableCell>
              <TableCell>{t('Duration')}</TableCell>
              <TableCell>{t('Participants')}</TableCell>
              <TableCell>{t('Status')}</TableCell>
              <TableCell>{t('Recurring')}</TableCell>
              <TableCell align="right">{t('Actions')}</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {sessions.map((session) => (
              <TableRow key={session.sessionID}>
                <TableCell>
                  <Box>
                    <Typography variant="subtitle2">
                      {session.title}
                    </Typography>
                    {session.meetingRoomURL && (
                      <Box sx={{ display: 'flex', alignItems: 'center', mt: 0.5 }}>
                        <VideoCallIcon sx={{ fontSize: 14, mr: 0.5 }} />
                        <Link
                          href={session.meetingRoomURL}
                          target="_blank"
                          rel="noopener noreferrer"
                          sx={{ 
                            display: 'flex', 
                            alignItems: 'center',
                            textDecoration: 'none',
                            '&:hover': { textDecoration: 'underline' }
                          }}
                        >
                          <Typography variant="caption" color="primary" sx={{ mr: 0.5 }}>
                            {t('Join Meeting')}
                          </Typography>
                          <OpenInNewIcon sx={{ fontSize: 12 }} />
                        </Link>
                      </Box>
                    )}
                  </Box>
                </TableCell>
                <TableCell>{getTeacherName(session.teacherID)}</TableCell>
                <TableCell>{getSpaceName(session.spaceID)}</TableCell>
                <TableCell>
                  <Typography variant="body2">
                    {new Date(session.dateTime).toLocaleDateString()}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {new Date(session.dateTime).toLocaleTimeString()}
                  </Typography>
                </TableCell>
                <TableCell>{session.duration} {t('min')}</TableCell>
                <TableCell>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <PeopleIcon sx={{ fontSize: 16, mr: 0.5 }} />
                    {getParticipantCount(session)}/50
                  </Box>
                </TableCell>
                <TableCell>{getStatusChip(session.status)}</TableCell>
                <TableCell>{getRecurringChip(getRecurringType(session))}</TableCell>
                <TableCell align="right">
                  <IconButton
                    onClick={(e) => handleMenuOpen(e, session.sessionID)}
                  >
                    <MoreVertIcon />
                  </IconButton>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>

      {/* Action Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
      >
        <MenuItem onClick={() => {
          const session = sessions.find(s => s.sessionID === menuSessionId);
          handleEditSession(session);
        }}>
          <ListItemIcon>
            <EditIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>{t('Edit')}</ListItemText>
        </MenuItem>
        <MenuItem onClick={() => handleDeleteSession(menuSessionId)}>
          <ListItemIcon>
            <DeleteIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>{t('Delete')}</ListItemText>
        </MenuItem>
      </Menu>

      {/* Create/Edit Session Dialog */}
      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          {isEditing ? t('Edit Session') : t('Create New Session')}
        </DialogTitle>
        <DialogContent>
          <Grid container spacing={2} sx={{ mt: 1 }}>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label={t('Session Title')}
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <FormControl fullWidth>
                <InputLabel>{t('Teacher')}</InputLabel>
                <Select
                  value={formData.teacherId}
                  onChange={(e) => setFormData({ ...formData, teacherId: e.target.value })}
                >
                  {mockTeachers.map(teacher => (
                    <MenuItem key={teacher.userID} value={teacher.userID}>
                      {teacher.firstName} {teacher.lastName}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} sm={6}>
              <FormControl fullWidth>
                <InputLabel>{t('Learning Space')}</InputLabel>
                <Select
                  value={formData.spaceId}
                  onChange={(e) => setFormData({ ...formData, spaceId: e.target.value })}
                >
                  {mockSpacesData.map(space => (
                    <MenuItem key={space.spaceID} value={space.spaceID}>
                      {space.spaceName}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                type="datetime-local"
                label={t('Start Time')}
                value={formData.startTime}
                onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                type="number"
                label={t('Duration (minutes)')}
                value={formData.duration}
                onChange={(e) => setFormData({ ...formData, duration: parseInt(e.target.value) })}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                type="number"
                label={t('Max Participants')}
                value={formData.maxParticipants}
                onChange={(e) => setFormData({ ...formData, maxParticipants: parseInt(e.target.value) })}
              />
            </Grid>
            <Grid item xs={12} sm={6}>
              <FormControl fullWidth>
                <InputLabel>{t('Recurring')}</InputLabel>
                <Select
                  value={formData.recurring}
                  onChange={(e) => setFormData({ ...formData, recurring: e.target.value })}
                >
                  <MenuItem value="none">{t('No repeat')}</MenuItem>
                  <MenuItem value="daily">{t('Daily')}</MenuItem>
                  <MenuItem value="weekly">{t('Weekly')}</MenuItem>
                  <MenuItem value="monthly">{t('Monthly')}</MenuItem>
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label={t('Meeting URL')}
                value={formData.meetingUrl}
                onChange={(e) => setFormData({ ...formData, meetingUrl: e.target.value })}
                placeholder="https://zoom.us/j/... or https://meet.google.com/..."
              />
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenDialog(false)}>
            {t('Cancel')}
          </Button>
          <Button
            variant="contained"
            onClick={handleSaveSession}
            disabled={!formData.title || !formData.teacherId || !formData.spaceId || !formData.startTime}
          >
            {isEditing ? t('Update') : t('Create')}
          </Button>
        </DialogActions>
      </Dialog>

      {/* Floating Action Button */}
      <Fab
        color="primary"
        aria-label="add session"
        sx={{ position: 'fixed', bottom: 80, right: 16 }}
        onClick={handleCreateSession}
      >
        <AddIcon />
      </Fab>
    </Box>
  );
} 