import React, { useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  CardActions,
  Button,
  Grid,
  Chip,
  Avatar,
  IconButton,
  Fab,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,

} from '@mui/material';
import {
  Add as AddIcon,
  People as PeopleIcon,
  School as SchoolIcon,
  Event as EventIcon,
  ExitToApp as LeaveIcon,
  Info as InfoIcon
} from '@mui/icons-material';
import { useTranslation } from 'react-i18next';
import { mockSpaces, mockSessions } from '../../data/mockData';

export default function SpacesPage() {
  const { t } = useTranslation();
  
  // Transform mockSpaces data to include computed fields
  const transformedSpaces = mockSpaces.map(space => {
    const sessionCount = mockSessions.filter(session => session.spaceID === space.spaceID).length;
    const memberCount = space.members ? space.members.length : 0;
    
    return {
      id: space.spaceID,
      name: space.spaceName,
      description: space.spaceDescription,
      memberCount: memberCount,
      sessionCount: sessionCount,
      joinedDate: space.createdDate ? space.createdDate.split('T')[0] : '2024-01-01',
      isAdmin: false, // Can be enhanced based on user role
      recentActivity: `Active space with ${sessionCount} sessions available`,
      language: space.language,
      spaceType: space.spaceType
    };
  });
  
  const [spaces] = useState(transformedSpaces);
  const [selectedSpace, setSelectedSpace] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [joinDialogOpen, setJoinDialogOpen] = useState(false);
  const [spaceCode, setSpaceCode] = useState('');

  const handleSpaceClick = (space) => {
    setSelectedSpace(space);
    setOpenDialog(true);
  };

  const handleJoinSpace = () => {
    // Implementation for joining a space with code
    setJoinDialogOpen(false);
    setSpaceCode('');
  };

  const handleLeaveSpace = (spaceId) => {
    // Implementation for leaving a space
    console.log('Leaving space:', spaceId);
  };

  return (
    <Box sx={{ p: 2, maxWidth: 1200, mx: 'auto' }}>
      <Typography variant="h4" gutterBottom>
        {t('Learning Spaces')}
      </Typography>
      
      <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
        {t('Join learning spaces to connect with teachers and fellow students')}
      </Typography>

      <Grid container spacing={3}>
        {spaces.map((space) => (
          <Grid item xs={12} md={6} lg={4} key={space.id}>
            <Card 
              sx={{ 
                height: '100%', 
                display: 'flex', 
                flexDirection: 'column',
                cursor: 'pointer',
                '&:hover': {
                  elevation: 4,
                  transform: 'translateY(-2px)',
                  transition: 'all 0.2s'
                }
              }}
              onClick={() => handleSpaceClick(space)}
            >
              <CardContent sx={{ flexGrow: 1 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Avatar sx={{ bgcolor: 'primary.main', mr: 2 }}>
                    <SchoolIcon />
                  </Avatar>
                  <Box sx={{ flexGrow: 1 }}>
                    <Typography variant="h6" component="h2">
                      {space.name}
                    </Typography>
                    <Box sx={{ display: 'flex', gap: 1, mt: 0.5, flexWrap: 'wrap' }}>
                      {space.isAdmin && (
                        <Chip 
                          size="small" 
                          label="Admin" 
                          color="primary"
                        />
                      )}
                      <Chip 
                        size="small" 
                        label={space.language.toUpperCase()} 
                        color="secondary" 
                        variant="outlined"
                      />
                      <Chip 
                        size="small" 
                        label={space.spaceType} 
                        color="default" 
                        variant="outlined"
                      />
                    </Box>
                  </Box>
                  <IconButton
                    size="small"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleLeaveSpace(space.id);
                    }}
                  >
                    <LeaveIcon />
                  </IconButton>
                </Box>

                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                  {space.description}
                </Typography>

                <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <PeopleIcon sx={{ fontSize: 16, mr: 0.5 }} />
                    <Typography variant="body2">
                      {space.memberCount} {t('members')}
                    </Typography>
                  </Box>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <EventIcon sx={{ fontSize: 16, mr: 0.5 }} />
                    <Typography variant="body2">
                      {space.sessionCount} {t('sessions')}
                    </Typography>
                  </Box>
                </Box>

                <Typography variant="body2" color="text.secondary" sx={{ fontStyle: 'italic' }}>
                  {space.recentActivity}
                </Typography>
              </CardContent>

              <CardActions>
                <Button 
                  size="small" 
                  startIcon={<InfoIcon />}
                  onClick={(e) => {
                    e.stopPropagation();
                    handleSpaceClick(space);
                  }}
                >
                  {t('View Details')}
                </Button>
              </CardActions>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* Floating Action Button to Join New Space */}
      <Fab 
        color="primary" 
        aria-label="join space"
        sx={{ position: 'fixed', bottom: 80, right: 16 }}
        onClick={() => setJoinDialogOpen(true)}
      >
        <AddIcon />
      </Fab>

      {/* Space Details Dialog */}
      <Dialog 
        open={openDialog} 
        onClose={() => setOpenDialog(false)}
        maxWidth="md"
        fullWidth
      >
        {selectedSpace && (
          <>
            <DialogTitle>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <Avatar sx={{ bgcolor: 'primary.main', mr: 2 }}>
                  <SchoolIcon />
                </Avatar>
                <Box>
                  <Typography variant="h6">{selectedSpace.name}</Typography>
                  <Typography variant="body2" color="text.secondary">
                    {t('Joined')} {new Date(selectedSpace.joinedDate).toLocaleDateString()}
                  </Typography>
                </Box>
              </Box>
            </DialogTitle>
            <DialogContent>
              <Typography paragraph>
                {selectedSpace.description}
              </Typography>
              
              <Grid container spacing={2} sx={{ mb: 2 }}>
                <Grid item xs={6}>
                  <Typography variant="subtitle2">{t('Members')}</Typography>
                  <Typography variant="h6">{selectedSpace.memberCount}</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="subtitle2">{t('Sessions')}</Typography>
                  <Typography variant="h6">{selectedSpace.sessionCount}</Typography>
                </Grid>
              </Grid>

              <Typography variant="subtitle2" gutterBottom>
                {t('Recent Activity')}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {selectedSpace.recentActivity}
              </Typography>
            </DialogContent>
            <DialogActions>
              <Button onClick={() => setOpenDialog(false)}>
                {t('Close')}
              </Button>
              <Button 
                variant="contained" 
                onClick={() => {
                  // Navigate to space details
                  setOpenDialog(false);
                }}
              >
                {t('Enter Space')}
              </Button>
            </DialogActions>
          </>
        )}
      </Dialog>

      {/* Join Space Dialog */}
      <Dialog 
        open={joinDialogOpen} 
        onClose={() => setJoinDialogOpen(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>{t('Join Learning Space')}</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            {t('Enter the space code provided by your teacher or administrator')}
          </Typography>
          <TextField
            autoFocus
            fullWidth
            label={t('Space Code')}
            value={spaceCode}
            onChange={(e) => setSpaceCode(e.target.value)}
            placeholder="e.g. ABC123"
            sx={{ mt: 1 }}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setJoinDialogOpen(false)}>
            {t('Cancel')}
          </Button>
          <Button 
            variant="contained" 
            onClick={handleJoinSpace}
            disabled={!spaceCode.trim()}
          >
            {t('Join Space')}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
} 