import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { mockNotifications, getUserNotifications } from '../data/mockData';

const NotificationContext = createContext();

export const useNotification = () => {
  const context = useContext(NotificationContext);
  if (!context) {
    throw new Error('useNotification must be used within a NotificationProvider');
  }
  return context;
};

export const NotificationProvider = ({ children }) => {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'info'
  });

  const loadUserNotifications = useCallback(() => {
    if (!user) return;
    const userNotifications = getUserNotifications(user.userID);
    setNotifications(userNotifications);
    setUnreadCount(userNotifications.filter(n => !n.isRead).length);
  }, [user]);

  useEffect(() => {
    if (user) {
      loadUserNotifications();
    } else {
      setNotifications([]);
      setUnreadCount(0);
    }
  }, [user, loadUserNotifications]);

  const markAsRead = (notificationId) => {
    setNotifications(prev => prev.map(notification => 
      notification.eventID === notificationId 
        ? { ...notification, isRead: true }
        : notification
    ));
    
    // Update unread count
    setUnreadCount(prev => Math.max(0, prev - 1));
    
    // Update mock data
    const notificationIndex = mockNotifications.findIndex(n => n.eventID === notificationId);
    if (notificationIndex !== -1) {
      mockNotifications[notificationIndex].isRead = true;
    }
  };

  const markAllAsRead = () => {
    setNotifications(prev => prev.map(notification => ({
      ...notification,
      isRead: true
    })));
    
    setUnreadCount(0);
    
    // Update mock data
    notifications.forEach(notification => {
      const notificationIndex = mockNotifications.findIndex(n => n.eventID === notification.eventID);
      if (notificationIndex !== -1) {
        mockNotifications[notificationIndex].isRead = true;
      }
    });
  };

  const deleteNotification = (notificationId) => {
    const notification = notifications.find(n => n.eventID === notificationId);
    
    setNotifications(prev => prev.filter(n => n.eventID !== notificationId));
    
    if (notification && !notification.isRead) {
      setUnreadCount(prev => Math.max(0, prev - 1));
    }
    
    // Remove from mock data
    const notificationIndex = mockNotifications.findIndex(n => n.eventID === notificationId);
    if (notificationIndex !== -1) {
      mockNotifications.splice(notificationIndex, 1);
    }
  };

  const createNotification = useCallback((notificationData) => {
    const newNotification = {
      eventID: `event_${Date.now()}`,
      eventType: notificationData.type || 'NOTIFICATION',
      title: notificationData.title,
      content: notificationData.content,
      fromUserID: notificationData.fromUserId || null,
      toUserID: user?.userID || null,
      spaceID: notificationData.spaceId || null,
      fromListeningSessionID: notificationData.sessionId || null,
      deliveryDate: new Date().toISOString(),
      isDelivered: true,
      isRead: false,
      priority: notificationData.priority || 'NORMAL',
      createdDate: new Date().toISOString()
    };

    // Add to notifications list
    setNotifications(prev => [newNotification, ...prev]);
    setUnreadCount(prev => prev + 1);
    
    // Add to mock data
    mockNotifications.unshift(newNotification);
    
    // Show snackbar notification
    showSnackbar(notificationData.title, 'info');
    
    return newNotification;
  }, [user]);

  const scheduleSessionReminder = (session, minutesBefore = 15) => {
    const sessionTime = new Date(session.dateTime);
    const reminderTime = new Date(sessionTime.getTime() - (minutesBefore * 60 * 1000));
    const now = new Date();
    
    if (reminderTime > now) {
      // In a real app, this would be handled by the backend/notification service
      setTimeout(() => {
        createNotification({
          type: 'REMINDER',
          title: `Session Reminder: ${session.title}`,
          content: `Your session "${session.title}" starts in ${minutesBefore} minutes. Click here to join: ${session.meetingRoomURL}`,
          sessionId: session.sessionID,
          priority: 'HIGH'
        });
      }, reminderTime.getTime() - now.getTime());
    }
  };

  const showSnackbar = (message, severity = 'info') => {
    setSnackbar({
      open: true,
      message,
      severity
    });
  };

  const hideSnackbar = () => {
    setSnackbar(prev => ({ ...prev, open: false }));
  };

  const showSuccess = (message) => showSnackbar(message, 'success');
  const showError = (message) => showSnackbar(message, 'error');
  const showWarning = (message) => showSnackbar(message, 'warning');
  const showInfo = (message) => showSnackbar(message, 'info');

  // Simulate real-time notifications (for demo purposes)
  useEffect(() => {
    if (!user) return;

    // eslint-disable-next-line no-unused-vars
    const simulateRealTimeNotifications = () => {
      // Simulate receiving a notification every 2 minutes (for demo)
      const demoNotifications = [
        {
          title: 'New Resource Available',
          content: 'A new meditation guide has been added to the resource library.',
          type: 'NOTIFICATION'
        },
        {
          title: 'Community Update',
          content: 'Your learning space "Beginner\'s Path" has a new announcement.',
          type: 'ANNOUNCEMENT'
        },
        {
          title: 'Weekly Dharma Talk',
          content: 'Join us this weekend for a special Dharma talk on compassion.',
          type: 'ANNOUNCEMENT'
        }
      ];

      let notificationIndex = 0;
      const interval = setInterval(() => {
        if (notificationIndex < demoNotifications.length) {
          createNotification(demoNotifications[notificationIndex]);
          notificationIndex++;
        } else {
          clearInterval(interval);
        }
      }, 120000); // Every 2 minutes

      return () => clearInterval(interval);
    };

    // Only simulate for demo - uncomment to enable
    // const cleanup = simulateRealTimeNotifications();
    // return cleanup;
  }, [user, createNotification]);

  const value = {
    notifications,
    unreadCount,
    snackbar,
    markAsRead,
    markAllAsRead,
    deleteNotification,
    createNotification,
    scheduleSessionReminder,
    showSnackbar,
    hideSnackbar,
    showSuccess,
    showError,
    showWarning,
    showInfo
  };

  return (
    <NotificationContext.Provider value={value}>
      {children}
    </NotificationContext.Provider>
  );
}; 