import React from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  Typography,
  Button,
  Box,
  Badge,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Divider,
  LinearProgress
} from '@mui/material';
import {
  Event,
  Schedule,
  Notifications,
  LibraryBooks,
  Person,
  Group,
  PlayArrow,
  BookmarkBorder
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';
import { 
  currentUser, 
  getUserSessions, 
  getUserEvents, 
  getUserSpaces,
  mockResources,
  getUserById
} from '../../data/mockData';

const StudentDashboard = () => {
  const navigate = useNavigate();
  
  // Get user's data
  const userSessions = getUserSessions(currentUser.userID);
  const userEvents = getUserEvents(currentUser.userID);
  const userSpaces = getUserSpaces(currentUser.userID);
  const unreadEvents = userEvents.filter(event => !event.isRead);
  
  // Get daily phrase
  const dailyPhrase = mockResources.find(r => r.resourceType === 'DAILY_PHRASE');

  // Get upcoming sessions (next 3)
  const upcomingSessions = userSessions
    .filter(session => new Date(session.dateTime) > new Date())
    .sort((a, b) => new Date(a.dateTime) - new Date(b.dateTime))
    .slice(0, 3);

  const formatSessionTime = (dateTime, timezone) => {
    const date = new Date(dateTime);
    return {
      date: format(date, 'MMM dd'),
      time: format(date, 'HH:mm'),
      day: format(date, 'EEE')
    };
  };

  return (
    <Container maxWidth="lg" sx={{ px: 2, pb: 2 }}>
      <Grid container spacing={2}>
        
        {/* Welcome Section */}
        <Grid item xs={12}>
          <Card sx={{ background: 'linear-gradient(135deg, #1976d2 0%, #42a5f5 100%)', color: 'white' }}>
            <CardContent>
              <Typography variant="h5" sx={{ fontWeight: 600, mb: 1 }}>
                Welcome back, {currentUser.firstName}!
              </Typography>
              <Typography variant="body2" sx={{ opacity: 0.9 }}>
                Continue your Buddhist learning journey with {upcomingSessions.length} upcoming sessions.
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        {/* Daily Phrase */}
        {dailyPhrase && (
          <Grid item xs={12}>
            <Card sx={{ borderLeft: '4px solid #ff9800' }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <BookmarkBorder sx={{ color: '#ff9800', mr: 1 }} />
                  <Typography variant="h6" sx={{ fontWeight: 600 }}>
                    Today's Dharma Reflection
                  </Typography>
                </Box>
                <Typography variant="body1" sx={{ fontStyle: 'italic', lineHeight: 1.6 }}>
                  {dailyPhrase.description}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        )}

        {/* Quick Actions */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" sx={{ mb: 2, fontWeight: 600 }}>
                Quick Actions
              </Typography>
              <Grid container spacing={2}>
                
                <Grid item xs={6} sm={3}>
                  <Button
                    fullWidth
                    variant="outlined"
                    startIcon={<Event />}
                    onClick={() => navigate('/sessions')}
                    sx={{ py: 1.5, flexDirection: 'column', gap: 0.5 }}
                  >
                    <Typography variant="caption">Browse</Typography>
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>Sessions</Typography>
                  </Button>
                </Grid>

                <Grid item xs={6} sm={3}>
                  <Button
                    fullWidth
                    variant="outlined"
                    startIcon={<LibraryBooks />}
                    onClick={() => navigate('/resources')}
                    sx={{ py: 1.5, flexDirection: 'column', gap: 0.5 }}
                  >
                    <Typography variant="caption">Explore</Typography>
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>Resources</Typography>
                  </Button>
                </Grid>

                <Grid item xs={6} sm={3}>
                  <Button
                    fullWidth
                    variant="outlined"
                    onClick={() => navigate('/notifications')}
                    sx={{ py: 1.5, flexDirection: 'column', gap: 0.5 }}
                    startIcon={
                      <Badge badgeContent={unreadEvents.length} color="error">
                        <Notifications />
                      </Badge>
                    }
                  >
                    <Typography variant="caption">Check</Typography>
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>Notifications</Typography>
                  </Button>
                </Grid>

                <Grid item xs={6} sm={3}>
                  <Button
                    fullWidth
                    variant="outlined"
                    startIcon={<Person />}
                    onClick={() => navigate('/profile')}
                    sx={{ py: 1.5, flexDirection: 'column', gap: 0.5 }}
                  >
                    <Typography variant="caption">Edit</Typography>
                    <Typography variant="body2" sx={{ fontWeight: 600 }}>Profile</Typography>
                  </Button>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        {/* Upcoming Sessions */}
        <Grid item xs={12} md={8}>
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                <Typography variant="h6" sx={{ fontWeight: 600 }}>
                  Upcoming Sessions
                </Typography>
                <Button 
                  size="small" 
                  onClick={() => navigate('/sessions')}
                  endIcon={<PlayArrow />}
                >
                  View All
                </Button>
              </Box>

              {upcomingSessions.length === 0 ? (
                <Box sx={{ textAlign: 'center', py: 4 }}>
                  <Event sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
                  <Typography variant="body1" color="text.secondary" sx={{ mb: 2 }}>
                    No upcoming sessions
                  </Typography>
                  <Button 
                    variant="contained" 
                    onClick={() => navigate('/sessions')}
                    startIcon={<Event />}
                  >
                    Browse Sessions
                  </Button>
                </Box>
              ) : (
                <List disablePadding>
                  {upcomingSessions.map((session, index) => {
                    const timeInfo = formatSessionTime(session.dateTime, session.timezone);
                    const teacher = getUserById(session.teacherID);
                    
                    return (
                      <React.Fragment key={session.sessionID}>
                        <ListItem 
                          sx={{ 
                            px: 0,
                            cursor: 'pointer',
                            borderRadius: 1,
                            '&:hover': { bgcolor: 'action.hover' }
                          }}
                          onClick={() => navigate(`/sessions/${session.sessionID}`)}
                        >
                          <ListItemAvatar>
                            <Avatar sx={{ bgcolor: 'primary.main' }}>
                              <Schedule />
                            </Avatar>
                          </ListItemAvatar>
                          
                          <ListItemText
                            primary={
                              <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                {session.title}
                              </Typography>
                            }
                            secondary={
                              <Box>
                                <Typography variant="body2" color="text.secondary">
                                  Teacher: {teacher?.firstName} {teacher?.lastName}
                                </Typography>
                                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mt: 0.5 }}>
                                  <Chip 
                                    label={`${timeInfo.day}, ${timeInfo.date}`}
                                    size="small"
                                    variant="outlined"
                                  />
                                  <Chip 
                                    label={timeInfo.time}
                                    size="small"
                                    color="primary"
                                  />
                                  <Chip 
                                    label={`${session.duration} min`}
                                    size="small"
                                    variant="outlined"
                                  />
                                </Box>
                              </Box>
                            }
                          />
                        </ListItem>
                        {index < upcomingSessions.length - 1 && <Divider />}
                      </React.Fragment>
                    );
                  })}
                </List>
              )}
            </CardContent>
          </Card>
        </Grid>

        {/* Activity Summary */}
        <Grid item xs={12} md={4}>
          <Grid container spacing={2}>
            
            {/* Learning Spaces */}
            <Grid item xs={12}>
              <Card>
                <CardContent>
                  <Typography variant="h6" sx={{ mb: 2, fontWeight: 600 }}>
                    My Learning Spaces
                  </Typography>
                  
                  {userSpaces.map((space) => (
                    <Box key={space.spaceID} sx={{ mb: 2 }}>
                      <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                        <Group sx={{ color: 'primary.main', mr: 1, fontSize: 20 }} />
                        <Typography variant="body2" sx={{ fontWeight: 500 }}>
                          {space.spaceName}
                        </Typography>
                      </Box>
                      <Typography variant="caption" color="text.secondary">
                        {space.spaceDescription}
                      </Typography>
                    </Box>
                  ))}
                </CardContent>
              </Card>
            </Grid>

            {/* Recent Notifications */}
            <Grid item xs={12}>
              <Card>
                <CardContent>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                    <Typography variant="h6" sx={{ fontWeight: 600 }}>
                      Recent Notifications
                    </Typography>
                    {unreadEvents.length > 0 && (
                      <Badge badgeContent={unreadEvents.length} color="error">
                        <Notifications />
                      </Badge>
                    )}
                  </Box>

                  {userEvents.length === 0 ? (
                    <Typography variant="body2" color="text.secondary">
                      No recent notifications
                    </Typography>
                  ) : (
                    <List disablePadding>
                      {userEvents.slice(0, 3).map((event, index) => (
                        <React.Fragment key={event.eventID}>
                          <ListItem 
                            sx={{ 
                              px: 0,
                              cursor: 'pointer',
                              opacity: event.isRead ? 0.7 : 1
                            }}
                            onClick={() => navigate('/notifications')}
                          >
                            <ListItemText
                              primary={
                                <Typography variant="body2" sx={{ fontWeight: event.isRead ? 400 : 600 }}>
                                  {event.title}
                                </Typography>
                              }
                              secondary={
                                <Typography variant="caption" color="text.secondary">
                                  {format(new Date(event.createdDate), 'MMM dd, HH:mm')}
                                </Typography>
                              }
                            />
                          </ListItem>
                          {index < Math.min(userEvents.length, 3) - 1 && <Divider />}
                        </React.Fragment>
                      ))}
                    </List>
                  )}

                  {userEvents.length > 3 && (
                    <Button 
                      size="small" 
                      fullWidth 
                      sx={{ mt: 1 }}
                      onClick={() => navigate('/notifications')}
                    >
                      View All Notifications
                    </Button>
                  )}
                </CardContent>
              </Card>
            </Grid>

            {/* Learning Progress */}
            <Grid item xs={12}>
              <Card>
                <CardContent>
                  <Typography variant="h6" sx={{ mb: 2, fontWeight: 600 }}>
                    Learning Progress
                  </Typography>
                  
                  <Box sx={{ mb: 2 }}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                      <Typography variant="body2">Sessions Attended</Typography>
                      <Typography variant="body2" sx={{ fontWeight: 600 }}>2/5</Typography>
                    </Box>
                    <LinearProgress variant="determinate" value={40} sx={{ height: 6, borderRadius: 3 }} />
                  </Box>

                  <Box sx={{ mb: 2 }}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                      <Typography variant="body2">Resources Explored</Typography>
                      <Typography variant="body2" sx={{ fontWeight: 600 }}>3/8</Typography>
                    </Box>
                    <LinearProgress variant="determinate" value={37.5} sx={{ height: 6, borderRadius: 3 }} />
                  </Box>

                  <Typography variant="caption" color="text.secondary">
                    Keep up the great work on your spiritual journey! 🧘‍♀️
                  </Typography>
                </CardContent>
              </Card>
            </Grid>
          </Grid>
        </Grid>
      </Grid>
    </Container>
  );
};

export default StudentDashboard; 