import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { Box, Typography, Paper, Alert } from '@mui/material';
import { SecurityOutlined } from '@mui/icons-material';
import { useAuth } from '../../contexts/AuthContext';

function ProtectedRoute({ 
  children, 
  requiredRoles = [], 
  requireAuth = true,
  fallbackPath = '/login' 
}) {
  const { user, hasAnyRole } = useAuth();
  const location = useLocation();

  // Check authentication
  if (requireAuth && !user) {
    return <Navigate to={fallbackPath} state={{ from: location }} replace />;
  }

  // Check role authorization
  if (user && requiredRoles.length > 0 && !hasAnyRole(requiredRoles)) {
    return (
      <Box
        sx={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          bgcolor: 'background.default',
          p: 3
        }}
      >
        <Paper
          elevation={2}
          sx={{
            p: 4,
            maxWidth: 400,
            textAlign: 'center',
            borderRadius: 2
          }}
        >
          <SecurityOutlined
            sx={{
              fontSize: 64,
              color: 'warning.main',
              mb: 2
            }}
          />
          
          <Typography variant="h5" gutterBottom sx={{ fontFamily: '"Noto Serif", serif' }}>
            Access Restricted
          </Typography>
          
          <Typography variant="body1" color="textSecondary" sx={{ mb: 3 }}>
            You don't have the required permissions to access this area.
          </Typography>
          
          <Alert severity="warning" sx={{ mb: 3 }}>
            <Typography variant="body2">
              <strong>Required roles:</strong> {requiredRoles.join(', ')}
              <br />
              <strong>Your roles:</strong> {user?.roles?.join(', ') || 'None'}
            </Typography>
          </Alert>
          
          <Typography variant="body2" color="textSecondary">
            Please contact an administrator if you believe you should have access to this area.
          </Typography>
        </Paper>
      </Box>
    );
  }

  return children;
}

export default ProtectedRoute; 